/// WS1-F2 slice 2 — report progress on a SINGLE plan step by its stable id, WITHOUT
/// re-sending the whole plan (weak-model-proof: nothing to paraphrase, nothing to
/// balloon). Rides the same merge + F2-verify path as update_plan.
fn step_advance_tool_schema() -> serde_json::Value {
    serde_json::json!({
        "type": "function",
        "function": {
            "name": "step_advance",
            "description": "Set a SINGLE plan step's new status by its id (e.g. move it to \"done\" when you finish it), WITHOUT re-sending the whole plan. This is the preferred way to report progress as you work; use update_plan only to CREATE or revise the plan. The id is shown in parentheses after each step's title in the Plan card.",
            "strict": true,
            "parameters": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "id": { "type": "string", "description": "The step id, EXACTLY as shown in the Plan card (e.g. \"s2\")." },
                    "status": { "type": "string", "enum": ["todo", "doing", "done", "blocked"], "description": "The step's new status." },
                    "detail": { "type": ["string", "null"], "description": "Optional updated detail." }
                },
                "required": ["id", "status", "detail"]
            }
        }
    })
}

/// Anti-churn: the harness appends a fresh ‹‹PLAN›› marker to the running message on
/// EVERY `update_plan`/`step_advance` call so the plan card animates live. The PERSISTED
/// message, though, must carry the plan card exactly ONCE — the latest canonical state —
/// not one block per tool call (a 5-step task that touches the plan 5× otherwise stores
/// 5 stacked ‹‹PLAN›› blocks = unreadable minestra, the agentic-loop regression).
///
/// Keep the LAST block's content (most steps closed = freshest canonical plan) but place
/// it at the FIRST block's position, so the card stays where the user first saw it instead
/// of jumping below the prose. All other blocks are removed; surrounding prose is intact.
/// `parse_plan_marker`'s resume still works: it `rfind`s the single remaining block.
/// Remove the app-only control markers (and their content) from a message before it
/// leaves the app to a plain-text surface — chiefly a channel mirror (Telegram/WhatsApp).
/// These markers (‹‹PLAN››, ‹‹ACT››, ‹‹ARTIFACT››, ‹‹REASONING››, ‹‹COMPOSIO_*››) are
/// rendered by the app UI; a channel must never receive them raw.
fn strip_chat_markers(text: &str) -> String {
    // Canonical stripper lives in the lib (shared with the in-app context renderer, caposaldo
    // #5). The channel mirror just wants the trimmed prose.
    strip_display_markers(text).trim().to_string()
}

/// F3-deep: true when an assembled answer carries NO answer body — only control markers
/// (chiefly a ‹‹REASONING›› trace) or nothing. This is the "non produce la risposta" failure:
/// a reasoning model that spent its whole token budget thinking (`finish_reason:length` with
/// empty content) leaves `‹‹REASONING››…‹‹/REASONING››` and no prose, so committing it would
/// Done an empty / reasoning-only bubble. `strip_chat_markers` removes every marker block, so
/// an empty remainder means there is no real answer to show.
fn answer_body_is_empty(content: &str) -> bool {
    strip_chat_markers(content).trim().is_empty()
}

/// The plan steps reconciled for delivery: EVERY still-open step forced to `done`, `blocked`
/// preserved. Returns `Some` only when reconciliation is enabled, a substantial answer was
/// delivered, and something actually changed — otherwise `None` (nothing to reconcile).
///
/// This is the single source of truth shared by the displayed ‹‹PLAN›› marker AND the
/// persisted runtime plan, so the two can never diverge (a text-only reconcile would show
/// the user 7/7 while the durable plan stays at 3/7 → `thread_has_active_runtime_plan` keeps
/// firing and the NEXT turn falsely resumes it).
///
/// It runs ONLY on the delivery path (25127/25242) — after the round loop has already DECIDED
/// to stop (nudges spent, round budget hit, or the model concluded). At that instant nothing
/// is "in progress" anymore, so a substantial final answer means the plan's work is delivered.
/// Models routinely answer the whole request but stop calling `step_advance` for the tail
/// (deepseek delivered all 7 markets yet left the plan frozen at 3/7 with a phantom "active"
/// step — the "non so a che punto è arrivato" symptom). `blocked` stays blocked: it's an
/// explicit failure the model recorded, not something to launder into success. The char floor
/// guards the genuinely-truncated case (budget burned, empty/short answer). NOTE: deliberately
/// does NOT reuse `answer_concludes_plan` — that predicate must stay conservative for the
/// *nudge* decision (25001), where many open steps means "keep pushing", the opposite intent.
fn plan_steps_reconciled_on_delivery(
    plan: &ExecutionPlan,
    text: &str,
) -> Option<Vec<serde_json::Value>> {
    if !plan_reconcile_on_delivery_enabled()
        || strip_chat_markers(text).trim().chars().count() < MIN_DELIVERED_CHARS_TO_CONCLUDE
    {
        return None;
    }
    let mut plan_steps = execution_plan_steps(plan);
    let mut changed = false;
    for step in plan_steps.iter_mut() {
        if !matches!(plan_step_status(step), "done" | "blocked") {
            step["status"] = serde_json::json!("done");
            changed = true;
        }
    }
    changed.then_some(plan_steps)
}

/// Thin text-only wrapper over `plan_steps_reconciled_on_delivery` — the delivery call sites
/// need the reconciled steps to ALSO persist the runtime plan, so they use the helper directly;
/// this convenience form (marker replacement only) is kept for the delivery-reconcile tests.
#[cfg(test)]
fn reconcile_final_plan_marker_on_delivery(plan: &ExecutionPlan, text: &str) -> String {
    match plan_steps_reconciled_on_delivery(plan, text) {
        Some(plan_steps) => replace_latest_plan_marker(text, &plan_steps),
        None => text.to_string(),
    }
}

fn plan_step_depends_on(step: &serde_json::Value) -> Vec<String> {
    step.get("depends_on")
        .and_then(|value| value.as_array())
        .into_iter()
        .flatten()
        .filter_map(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .collect()
}

// --- F4: cross-turn plan-stall guard -------------------------------------------------
//
// The per-turn recovery counters (nav-fail `nav_failures`, round budget
// `rounds_since_progress`) are reset every turn. A plan RESUMED across turns
// (`load_runtime_plan_from_state`, channel/resume) therefore restarts its current step with
// the counters at zero — so a step that fails deterministically (dead URL, unfillable form)
// retries forever, once per resume. The fix is a CROSS-turn signal: count consecutive resumes
// that close NO new step; after the cap the harness blocks the stuck step (caposaldo #2 — the
// harness owns recovery, the model won't pivot on its own). The pure pieces live here, tested.

/// Max consecutive resumes of a plan with no new completed step before the harness blocks the
/// stuck step. Generous on purpose: a plan legitimately advancing even one step per turn never
/// trips (any `done`-count increase resets the counter); only genuine no-progress loops do.
const MAX_PLAN_STALL_RESUMES: u32 = 3;

/// New stall count from the prior count and the done-counts at the previous vs the current
/// resume. ANY progress (more done steps than last resume) resets to 0; otherwise +1. Pure.
fn next_plan_stall(prior_stall: u32, last_resume_done: usize, current_done: usize) -> u32 {
    if current_done > last_resume_done {
        0
    } else {
        prior_stall.saturating_add(1)
    }
}

fn plan_stall_exhausted(stall: u32) -> bool {
    stall >= MAX_PLAN_STALL_RESUMES
}

/// Block the first runnable (`todo`/`doing`) step — the F4 abort action once a plan has
/// stalled across resumes. Records WHY in the step's `detail` (surfaced in the Plan panel).
/// Returns the blocked step's title, or None if nothing was runnable. Pure (mutates `plan`).
fn block_stalled_step(plan: &mut [serde_json::Value]) -> Option<String> {
    for step in plan.iter_mut() {
        if matches!(plan_step_status(step), "todo" | "doing") {
            let title = plan_step_title(step).to_string();
            step["status"] = serde_json::json!("blocked");
            step["detail"] = serde_json::json!(format!(
                "paused by the harness: no progress after {MAX_PLAN_STALL_RESUMES} resumed turns"
            ));
            return Some(title).filter(|t| !t.is_empty());
        }
    }
    None
}

/// F4 abort is hot-path control-flow that can't be validated live in this environment, so it
/// ships gated (same discipline as `HOMUN_PLAN_RECONCILE`). Flip on to validate. The pure
/// stall math and the `settled`-termination it relies on are always active and tested.
fn plan_stall_abort_enabled() -> bool {
    std::env::var("HOMUN_PLAN_STALL_ABORT")
        .map(|value| value == "1" || value.eq_ignore_ascii_case("on"))
        .unwrap_or(false)
}

// `MIN_DELIVERED_CHARS_TO_CONCLUDE` + `answer_concludes_plan` moved to `engine::plan`
// (ADR 0024 inc 5e.3); imported below.

/// F2.2 (ADR 0018, Pavimento): when the over-running guard accepts the answer with the last
/// step still open, reconcile that step to `done` so the PERSISTED runtime plan reflects the
/// delivered work. Without it the plan stays "active" and the NEXT turn falsely resumes it
/// (`thread_has_active_runtime_plan` only goes quiet when the plan is complete→Stale) — the
/// "lo segue e non lo segue" symptom. Default-on after live evidence showed the Plan panel
/// stuck at 1/2 while the delivered answer had already registered the last-step failure.
/// `HOMUN_PLAN_RECONCILE=0`/`off` remains as a diagnostic opt-out.
fn plan_reconcile_on_delivery_flag(value: Option<&str>) -> bool {
    match value.map(str::trim).filter(|value| !value.is_empty()) {
        Some(value) if value == "0" || value.eq_ignore_ascii_case("off") => false,
        _ => true,
    }
}

fn plan_reconcile_on_delivery_enabled() -> bool {
    plan_reconcile_on_delivery_flag(std::env::var("HOMUN_PLAN_RECONCILE").ok().as_deref())
}

/// Harness-driven plan progress during a browsing turn. When the driver switches to the
/// (weaker) browser model for the rest of the turn (see the browser branch), that model stops
/// calling `step_advance`, so the Plan card freezes at the frontier while markets are actually
/// being read — then jumps to N/N only at the final delivery reconcile. With this ON the harness
/// itself advances the frontier step as soon as the gathered evidence VERIFIES it (reusing the
/// F2 judge), so progress rises in real time without trusting the weak model. Same default-on +
/// diagnostic opt-out (`HOMUN_PLAN_AUTOADVANCE=0`/`off`) as the delivery reconcile.
fn plan_autoadvance_from_evidence_enabled() -> bool {
    plan_reconcile_on_delivery_flag(std::env::var("HOMUN_PLAN_AUTOADVANCE").ok().as_deref())
}

/// ADR 0022 — Tappa 1: instrada brief/recall/learn tramite `MemoryRecallService`
/// invece dell'orchestrazione inline. Default OFF (parità conservativa); flip ON
/// per validare l'incapsulamento. Stessa disciplina di `plan_stall_abort_enabled`.
fn memory_service_enabled() -> bool {
    std::env::var("HOMUN_MEMORY_SERVICE")
        .map(|value| value == "1" || value.eq_ignore_ascii_case("on"))
        .unwrap_or(false)
}

fn browser_open_research_discovery_instruction() -> &'static str {
    "For open-ended current news or broad web research where the user did NOT name \
a specific site/URL, start with search/discovery (for example a search results or \
news discovery page), scan multiple recent candidates, then choose the best sources. \
match the user's language and the browser locale when choosing discovery pages; when \
using a search/news URL, include locale parameters such as hl=it and gl=IT when \
appropriate instead of defaulting to an unrelated market. \
Do not jump directly to one outlet unless the user explicitly named it."
}

fn booking_assumption_choice_instruction() -> &'static str {
    "For bookings, purchases, or other real-world transactions, do NOT silently proceed \
with an assumed critical parameter (departure city/station, destination, date/time, quantity, \
budget, passenger count, etc.). If you have a likely default from context, STOP and emit a \
CHOICES marker with one option that confirms the default and one option for free-text correction \
(for example: Confirm Milan departure / Choose another departure). Continue only after the user \
chooses or writes the missing value."
}

fn runtime_plan_thread_key(thread_id: Option<&str>) -> String {
    thread_id
        .map(str::trim)
        .filter(|id| !id.is_empty())
        .unwrap_or("__no_thread__")
        .to_string()
}

fn runtime_plan_memory_text(plan: &[serde_json::Value]) -> Option<String> {
    if plan.is_empty() {
        return None;
    }
    let done = plan_done_count(plan);
    let total = plan.len();
    let next = plan_next_open(plan);
    let mut parts = vec![format!("Runtime plan state: {done}/{total} steps done.")];
    if plan_is_complete(plan) {
        parts.push("Plan is complete.".to_string());
    } else {
        match next {
            Some(step) => parts.push(format!("Next step: {step}.")),
            None => {
                parts.push("Plan is blocked or unfinished with no runnable next step.".to_string())
            }
        }
    }
    Some(parts.join(" "))
}

fn runtime_plan_memory_metadata(
    thread_id: Option<&str>,
    plan: &[serde_json::Value],
) -> serde_json::Value {
    serde_json::json!({
        "source": "runtime_plan",
        "thread_id": runtime_plan_thread_key(thread_id),
        "status": if plan_is_complete(plan) { "complete" } else { "open" },
        "done_count": plan_done_count(plan),
        "total_count": plan.len(),
        "next_step": plan_next_open(plan),
        "steps": plan,
        "execution_plan": runtime_execution_plan(plan),
    })
}

/// The gateway's typed `ExecutionPlan` from `LoopState.plan`'s opaque `Value` (ADR 0024 inc 5,
/// P5). The inverse of `serde_json::to_value(&ExecutionPlan)`: the loop carries the plan as a
/// `Value` (engine-safe), but the ExecutionPlan-only helpers (`merge_execution_plan`,
/// `plan_steps_reconciled_on_delivery`) still need the typed form. A faithful round-trip in
/// practice (the Value is always `to_value(&ExecutionPlan)`); an empty plan is the safe fallback
/// for `Null`/malformed, matching the old `runtime_execution_plan(&[])` seed.
fn plan_value_from(plan: &serde_json::Value) -> ExecutionPlan {
    serde_json::from_value::<ExecutionPlan>(plan.clone()).unwrap_or_else(|_| runtime_execution_plan(&[]))
}

fn runtime_execution_plan(plan: &[serde_json::Value]) -> ExecutionPlan {
    ExecutionPlan {
        route: OrchestratorRoute::MixedWorkflow,
        direct_answer: None,
        plan_propose: None,
        steps: plan
            .iter()
            .enumerate()
            .filter_map(|(index, step)| {
                let title = plan_step_title(step).trim();
                if title.is_empty() {
                    return None;
                }
                let step_id = plan_step_id(step)
                    .map(str::to_string)
                    .unwrap_or_else(|| format!("s{}", index + 1));
                Some(PlanStep {
                    step_id,
                    kind: PlanStepKind::DirectAnswer,
                    depends_on: plan_step_depends_on(step),
                    provider_id: None,
                    tool_name: None,
                    arguments: serde_json::json!({
                        "title": title,
                        "status": plan_step_status(step),
                        "detail": step.get("detail").cloned().unwrap_or(serde_json::Value::Null),
                        "done_criterion": step
                            .get("done_criterion")
                            .cloned()
                            .unwrap_or(serde_json::Value::Null),
                    }),
                    execution_policy: StepExecutionPolicy::Immediate,
                    risk_level: "low".to_string(),
                    expected_duration_seconds: 0,
                    agent_id: None,
                    goal: Some(title.to_string()),
                    contract: Some("runtime_plan_step".to_string()),
                    allowed_actions: vec![],
                    requires_user_approval: None,
                    timeout_seconds: None,
                    max_tokens: None,
                })
            })
            .collect(),
        needs_more_tools: None,
    }
}

fn execution_plan_steps(plan: &ExecutionPlan) -> Vec<serde_json::Value> {
    plan.steps
        .iter()
        .map(|step| {
            let title = step
                .arguments
                .get("title")
                .and_then(|value| value.as_str())
                .or(step.goal.as_deref())
                .unwrap_or("")
                .to_string();
            serde_json::json!({
                "id": step.step_id,
                "title": title,
                "status": step.arguments
                    .get("status")
                    .and_then(|value| value.as_str())
                    .unwrap_or("todo"),
                "detail": step.arguments
                    .get("detail")
                    .cloned()
                    .unwrap_or(serde_json::Value::Null),
                "done_criterion": step.arguments
                    .get("done_criterion")
                    .cloned()
                    .unwrap_or(serde_json::Value::Null),
                "depends_on": step.depends_on,
            })
        })
        .collect()
}

fn merge_execution_plan(plan: &mut ExecutionPlan, sent: &[serde_json::Value]) -> Vec<usize> {
    let mut steps = execution_plan_steps(plan);
    let claims = merge_plan(&mut steps, sent);
    // Derive completion of earlier steps from the current frontier (see helper) so the
    // persisted plan — and thus every surface that renders it — reflects real progress.
    enforce_monotonic_plan_progress(&mut steps);
    let mut previous_steps = std::mem::take(&mut plan.steps);
    plan.steps = steps
        .iter()
        .filter_map(|step_view| {
            let step_id = plan_step_id(step_view)?.to_string();
            if let Some(index) = previous_steps
                .iter()
                .position(|step| step.step_id == step_id)
            {
                let mut step = previous_steps.remove(index);
                apply_execution_plan_step_view(&mut step, step_view);
                Some(step)
            } else {
                runtime_execution_plan(std::slice::from_ref(step_view))
                    .steps
                    .into_iter()
                    .next()
            }
        })
        .collect();
    claims
}

fn apply_execution_plan_step_view(step: &mut PlanStep, step_view: &serde_json::Value) {
    if !plan_step_depends_on(step_view).is_empty() {
        step.depends_on = plan_step_depends_on(step_view);
    }
    if !step.arguments.is_object() {
        step.arguments = serde_json::json!({});
    }
    if let Some(arguments) = step.arguments.as_object_mut() {
        arguments.insert(
            "title".to_string(),
            serde_json::json!(plan_step_title(step_view)),
        );
        arguments.insert(
            "status".to_string(),
            serde_json::json!(plan_step_status(step_view)),
        );
        arguments.insert(
            "detail".to_string(),
            step_view
                .get("detail")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
        );
        arguments.insert(
            "done_criterion".to_string(),
            step_view
                .get("done_criterion")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
        );
    }
}

#[derive(Debug, Clone)]
struct WorkflowStepDefinition {
    id: &'static str,
    title: &'static str,
    depends_on: &'static [&'static str],
}

#[derive(Debug, Clone)]
struct WorkflowDefinition {
    id: &'static str,
    tool_name: &'static str,
    contract: &'static str,
    steps: &'static [WorkflowStepDefinition],
}

#[derive(Debug, Clone, Copy)]
struct NativeWorkflowCapability {
    workflow_id: &'static str,
    tool_name: &'static str,
    contract: &'static str,
    scaffolding_tier: &'static str,
    description: &'static str,
    route_text: &'static str,
    schema: fn() -> serde_json::Value,
}

#[derive(Debug, Clone, Copy)]
struct NativeAtomicCapability {
    key: &'static str,
    tool_name: &'static str,
    description: &'static str,
    route_text: &'static str,
    schema: fn() -> serde_json::Value,
}

#[derive(Debug, Clone)]
struct TemplateCatalogEntry {
    provider: String,
    id: String,
    name: String,
    kind: String,
    description: String,
    use_cases: Vec<String>,
    audience: Vec<String>,
    design_template: String,
    design_theme: Option<String>,
    design_profile: Option<String>,
    design_components: Vec<String>,
    layout_archetypes: Vec<String>,
    tags: Vec<String>,
    preview_ref: Option<String>,
    source_ref: Option<String>,
    license: Option<String>,
    source_provider: Option<String>,
    source_path: Option<PathBuf>,
    template_pack_root: Option<PathBuf>,
    attribution_required: bool,
    attribution_text: Option<String>,
    redistribution_policy: Option<String>,
    route_text: String,
}

trait TemplateCatalogProvider {
    fn provider_id(&self) -> &str;
    fn entries(&self) -> Vec<TemplateCatalogEntry>;

    fn get(&self, id: &str) -> Option<TemplateCatalogEntry> {
        template_catalog_by_id_from_entries(&self.entries(), Some(id))
    }
}

struct LocalTemplateCatalogProvider;

#[derive(Debug, Clone)]
struct FileTemplateCatalogProvider {
    provider_id: String,
    entries: Vec<TemplateCatalogEntry>,
}

#[derive(Debug, Clone)]
struct ImportedTemplatePackProvider {
    entries: Vec<TemplateCatalogEntry>,
}

