fn workflow_execution_plan(
    definition: &WorkflowDefinition,
    arguments: serde_json::Value,
) -> ExecutionPlan {
    ExecutionPlan {
        route: OrchestratorRoute::MixedWorkflow,
        direct_answer: None,
        plan_propose: None,
        steps: definition
            .steps
            .iter()
            .map(|step| PlanStep {
                step_id: step.id.to_string(),
                kind: PlanStepKind::DirectAnswer,
                depends_on: step
                    .depends_on
                    .iter()
                    .map(|value| value.to_string())
                    .collect(),
                provider_id: None,
                tool_name: Some(definition.tool_name.to_string()),
                arguments: serde_json::json!({
                    "workflow_id": definition.id,
                    "step_title": step.title,
                    "input": arguments,
                }),
                execution_policy: StepExecutionPolicy::Immediate,
                risk_level: "low".to_string(),
                expected_duration_seconds: 0,
                agent_id: None,
                goal: Some(step.title.to_string()),
                contract: Some(definition.contract.to_string()),
                allowed_actions: vec![],
                requires_user_approval: None,
                timeout_seconds: None,
                max_tokens: None,
            })
            .collect(),
        needs_more_tools: None,
    }
}

fn run_static_workflow_plan_through_brain(
    goal: &str,
    plan: ExecutionPlan,
) -> Result<ExecutionPlan, String> {
    let router = build_browser_inference_router();
    let mut brain = OrchestratorBrain::new(
        router,
        GatewayBrainMemory(None),
        CapabilityFacade::new(
            CapabilityPolicy::default(),
            InMemoryCapabilityAudit::default(),
        ),
        TaskStore::open_in_memory().map_err(|error| error.to_string())?,
    );
    let user = gateway_capability_user_id();
    let workspace = gateway_capability_workspace_id();
    let request = OrchestratorRequest {
        request_id: format!("static_workflow_{}", uuid::Uuid::new_v4().simple()),
        policy_context: PolicyContext {
            user_id: user,
            workspace_id: workspace,
            enabled_providers: Vec::new(),
            privacy_domains: vec!["work".to_string()],
            allowed_actions: vec![ActionClass::Read, ActionClass::Draft],
            max_autonomy_level: 0,
            allow_managed_cloud: false,
        },
        user_message: goal.to_string(),
        conversation_summary: None,
        attachments: Vec::new(),
        budgets: brain_budgets_for_context_window(None),
        language: effective_user_language(),
    };
    let outcome = brain
        .run_plan(request, plan)
        .map_err(|error| error.to_string())?;
    Ok(outcome.plan)
}

async fn run_static_workflow_plan_through_brain_async(
    goal: String,
    plan: ExecutionPlan,
) -> Result<ExecutionPlan, String> {
    tokio::task::spawn_blocking(move || run_static_workflow_plan_through_brain(&goal, plan))
        .await
        .map_err(|error| format!("static workflow validation join error: {error}"))?
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum WorkflowRouteDecision {
    Workflow {
        workflow_id: &'static str,
        tool_name: &'static str,
        scaffolding_tier: &'static str,
    },
    AgentLoop,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum CapabilityRouteDecision {
    Workflow {
        workflow_id: &'static str,
        tool_name: &'static str,
        scaffolding_tier: &'static str,
        reason: String,
        alternatives: Vec<String>,
    },
    AtomicTool {
        capability_key: &'static str,
        reason: String,
    },
    AgentLoop {
        reason: String,
    },
}

fn route_workflow_or_agent(prompt: &str) -> WorkflowRouteDecision {
    workflow_route_from_capability(&route_capability(prompt))
}

fn workflow_route_from_capability(decision: &CapabilityRouteDecision) -> WorkflowRouteDecision {
    match decision {
        CapabilityRouteDecision::Workflow {
            workflow_id,
            tool_name,
            scaffolding_tier,
            ..
        } => WorkflowRouteDecision::Workflow {
            workflow_id,
            tool_name,
            scaffolding_tier,
        },
        CapabilityRouteDecision::AtomicTool { .. } | CapabilityRouteDecision::AgentLoop { .. } => {
            WorkflowRouteDecision::AgentLoop
        }
    }
}

fn route_capability(prompt: &str) -> CapabilityRouteDecision {
    if let Some(reason) = atomic_pdf_operation_reason(prompt) {
        return CapabilityRouteDecision::AtomicTool {
            capability_key: "pdf_atomic",
            reason,
        };
    }

    let entries = native_workflow_capability_entries();
    let Some(entry) = bm25_rank(&entries, prompt, 1).into_iter().next() else {
        return CapabilityRouteDecision::AgentLoop {
            reason: "No native workflow candidate matched the request.".to_string(),
        };
    };
    if let Some(capability) = native_workflow_by_tool_name(&entry.key) {
        let alternatives = entries
            .iter()
            .filter(|candidate| candidate.key != entry.key)
            .map(|candidate| candidate.key.clone())
            .collect();
        return CapabilityRouteDecision::Workflow {
            workflow_id: capability.workflow_id,
            tool_name: capability.tool_name,
            scaffolding_tier: capability.scaffolding_tier,
            reason: format!(
                "Selected `{}` from the native workflow registry via BM25 over semantic route text.",
                capability.tool_name
            ),
            alternatives,
        };
    }
    CapabilityRouteDecision::AgentLoop {
        reason: "The best capability candidate was not a native workflow.".to_string(),
    }
}

fn atomic_pdf_operation_reason(prompt: &str) -> Option<String> {
    let tokens: std::collections::BTreeSet<String> = cap_tokenize(prompt).into_iter().collect();
    let mentions_pdf = tokens.contains("pdf");
    if !mentions_pdf {
        return None;
    }
    let atomic_actions = [
        "estrai", "estrarre", "extract", "leggi", "read", "unisci", "merge", "combina", "combine",
        "converti", "convert", "comprimi", "compress", "split", "dividi",
    ];
    let matched = atomic_actions
        .iter()
        .find(|action| tokens.contains(**action))?;
    Some(format!(
        "PDF action `{matched}` is an atomic document operation, not an end-to-end document creation workflow."
    ))
}

#[cfg(test)]
fn workflow_router_instruction(prompt: &str) -> Option<String> {
    let decision = route_workflow_or_agent(prompt);
    workflow_router_instruction_for_decision(&decision)
}

fn workflow_router_instruction_for_decision(decision: &WorkflowRouteDecision) -> Option<String> {
    match decision {
        WorkflowRouteDecision::Workflow {
            workflow_id,
            tool_name,
            scaffolding_tier,
        } => Some(format!(
            "WORKFLOW ROUTER: this request is routed by the harness to workflow `{workflow_id}` \
with `{scaffolding_tier}` scaffolding. Call `{tool_name}` exactly once with the user's brief; \
do not create a separate plan, do not decompose it into lower-level tools, and do not use shell/file tools for this workflow."
        )),
        WorkflowRouteDecision::AgentLoop => None,
    }
}

fn capability_router_instruction_for_decision(
    decision: &CapabilityRouteDecision,
) -> Option<String> {
    match decision {
        CapabilityRouteDecision::Workflow {
            workflow_id,
            tool_name,
            scaffolding_tier,
            reason,
            ..
        } => Some(format!(
            "CAPABILITY ROUTER: this request is routed by the harness to workflow `{workflow_id}` \
with `{scaffolding_tier}` scaffolding. Reason: {reason} Call `{tool_name}` exactly once with the user's brief; \
do not create a separate plan, do not decompose it into lower-level tools, and do not use shell/file tools for this workflow."
        )),
        CapabilityRouteDecision::AtomicTool {
            capability_key,
            reason,
        } => Some(format!(
            "CAPABILITY ROUTER: this request is classified as atomic capability `{capability_key}`. \
Reason: {reason} Do not call end-to-end deliverable workflows such as `make_document` for this request. \
Use the most specific atomic/tool capability available, or call `find_capability` if it is not already loaded."
        )),
        CapabilityRouteDecision::AgentLoop { .. } => None,
    }
}

fn capability_route_trace_line(decision: &CapabilityRouteDecision) -> Option<String> {
    match decision {
        CapabilityRouteDecision::Workflow {
            workflow_id,
            tool_name,
            reason,
            alternatives,
            ..
        } => Some(format!(
            "capability route: workflow {workflow_id}/{tool_name}; reason={reason}; alternatives={}",
            if alternatives.is_empty() {
                "none".to_string()
            } else {
                alternatives.join(",")
            }
        )),
        CapabilityRouteDecision::AtomicTool {
            capability_key,
            reason,
        } => Some(format!(
            "capability route: atomic {capability_key}; reason={reason}"
        )),
        CapabilityRouteDecision::AgentLoop { .. } => None,
    }
}

/// Adaptive floor (ADR 0018, Fase 2): relax a Workflow route to AgentLoop for a
/// CAPABLE model so it is not forced into the one-shot workflow box. The workflow
/// tool stays OFFERED elsewhere; this only drops the pruning + "exactly once"
/// binding + blocked-tool guard. Weak/Balanced or `floor_on == false` are
/// unchanged; AtomicTool is never relaxed. Pure so it can be unit-tested.
fn relax_route_for_tier(
    route: CapabilityRouteDecision,
    bias: scaffold::WorkflowBias,
    floor_on: bool,
) -> CapabilityRouteDecision {
    if floor_on
        && bias == scaffold::WorkflowBias::AllowAgentic
        && matches!(route, CapabilityRouteDecision::Workflow { .. })
    {
        return CapabilityRouteDecision::AgentLoop {
            reason: "Adaptive floor: capable model kept on the agent loop with the workflow tool still available."
                .to_string(),
        };
    }
    route
}

fn prune_tools_for_workflow_route(
    tools: &mut Vec<serde_json::Value>,
    route: &WorkflowRouteDecision,
) {
    if let WorkflowRouteDecision::Workflow { tool_name, .. } = route {
        tools.retain(|schema| {
            schema
                .pointer("/function/name")
                .and_then(|value| value.as_str())
                == Some(*tool_name)
        });
    }
}

fn workflow_route_blocked_tool_message(
    route: &CapabilityRouteDecision,
    tool_name: &str,
) -> Option<String> {
    match route {
        CapabilityRouteDecision::Workflow {
            workflow_id,
            tool_name: workflow_tool,
            ..
        } if tool_name != *workflow_tool => Some(format!(
            "WORKFLOW_ROUTE_BLOCKED_TOOL: this turn is routed to workflow `{workflow_id}`. \
Tool `{tool_name}` is not allowed here. Do not create files manually, do not use shell/filesystem \
fallbacks, and do not decompose the workflow. Use `{workflow_tool}` exactly once; if `{workflow_tool}` \
already failed because the provider is unavailable, stop and tell the user to choose a reachable \
provider or start the required local service."
        )),
        _ => None,
    }
}

fn runtime_plan_memory_matches(memory: &MemoryRecord, thread_key: &str) -> bool {
    memory.memory_type == "open_loop"
        && !matches!(
            memory.status,
            MemoryStatus::Deleted | MemoryStatus::Rejected | MemoryStatus::Stale
        )
        && memory.metadata.get("source").and_then(|v| v.as_str()) == Some("runtime_plan")
        && memory.metadata.get("thread_id").and_then(|v| v.as_str()) == Some(thread_key)
}

/// True if this thread has an IN-PROGRESS runtime plan. A completed plan is marked
/// Stale (see `upsert_runtime_plan_memory`) and excluded by `runtime_plan_memory_matches`,
/// so this only fires while a plan is genuinely open.
///
/// The plan is harness-owned control flow (Pavimento — see docs/architecture/agent-loop.md
/// and ADR 0018): an active plan must take precedence over the workflow-bias *manopola*.
/// Without this, a continuation turn can be routed into a one-shot workflow (`make_deck`),
/// which prunes the plan's own tools (`update_plan`, `browser_navigate`) and dead-ends it.
/// Tier- and flag-independent: it holds even with the adaptive floor off.
fn thread_has_active_runtime_plan(state: &AppState, thread_id: Option<&str>) -> bool {
    let thread_key = runtime_plan_thread_key(thread_id);
    let Ok(facade) = lock_memory_facade(state) else {
        return false;
    };
    facade
        .list_memories_for_ui(&gateway_memory_user_id(), &gateway_memory_workspace_id())
        .unwrap_or_default()
        .iter()
        .any(|memory| runtime_plan_memory_matches(memory, &thread_key))
}

/// Load the thread's CANONICAL plan steps from the durable runtime-plan store (the same
/// per-thread memory `thread_has_active_runtime_plan` matches). This is the authoritative
/// cross-turn state: it's upserted on EVERY `update_plan`/`step_advance` (synchronously,
/// before a turn ends), so a CONTINUATION turn can inherit `{done,doing,…}` even before the
/// prior turn's ‹‹PLAN›› message has been persisted/streamed into the next turn's context.
/// Returns the steps (with verified statuses) or empty if the thread has no open plan.
fn load_runtime_plan_from_state(
    state: &AppState,
    thread_id: Option<&str>,
) -> Vec<serde_json::Value> {
    let thread_key = runtime_plan_thread_key(thread_id);
    let Ok(facade) = lock_memory_facade(state) else {
        return Vec::new();
    };
    facade
        .list_memories_for_ui(&gateway_memory_user_id(), &gateway_memory_workspace_id())
        .unwrap_or_default()
        .iter()
        .find(|memory| runtime_plan_memory_matches(memory, &thread_key))
        .and_then(|memory| {
            memory
                .metadata
                .get("steps")
                .and_then(|s| s.as_array())
                .cloned()
        })
        .unwrap_or_default()
}

/// F4 turn-start: update the cross-turn stall bookkeeping on the RESUMED plan's memory and
/// report whether it has stalled past the cap. Reads `{stall_turns, last_resume_done}` from
/// the plan-memory metadata, recomputes them against the current done-count, writes them back
/// (so a mid-turn plan upsert preserves them — `upsert_runtime_plan_memory` carries these
/// fields forward), and returns true when the harness should block the stuck step. A no-op
/// returning false on any store miss (fail-open: never wedge a turn over bookkeeping).
fn plan_stall_check_and_bump(
    state: &AppState,
    thread_id: Option<&str>,
    resume_plan: &[serde_json::Value],
) -> bool {
    let thread_key = runtime_plan_thread_key(thread_id);
    let Ok(facade) = lock_memory_facade(state) else {
        return false;
    };
    let user = gateway_memory_user_id();
    let workspace = gateway_memory_workspace_id();
    let Some(memory) = facade
        .list_memories_for_ui(&user, &workspace)
        .unwrap_or_default()
        .into_iter()
        .find(|memory| runtime_plan_memory_matches(memory, &thread_key))
    else {
        return false;
    };
    let prior_stall = memory
        .metadata
        .get("stall_turns")
        .and_then(|v| v.as_u64())
        .unwrap_or(0) as u32;
    let last_resume_done = memory
        .metadata
        .get("last_resume_done")
        .and_then(|v| v.as_u64())
        .unwrap_or(0) as usize;
    let current_done = plan_done_count(resume_plan);
    let new_stall = next_plan_stall(prior_stall, last_resume_done, current_done);

    let mut metadata = memory.metadata.clone();
    if let Some(obj) = metadata.as_object_mut() {
        obj.insert("stall_turns".to_string(), serde_json::json!(new_stall));
        obj.insert(
            "last_resume_done".to_string(),
            serde_json::json!(current_done),
        );
    }
    let lifecycle = MemoryLifecycleRequest {
        actor_id: "runtime-plan".to_string(),
        user_id: user.clone(),
        workspace_id: workspace.clone(),
        purpose: "sync_runtime_plan".to_string(),
    };
    let _ = facade.update_memory(
        &lifecycle,
        &memory.reference,
        MemoryUpdatePatch {
            text: None,
            aliases: None,
            language_hints: None,
            confidence: None,
            privacy_domain: None,
            sensitivity: None,
            metadata: Some(metadata),
            last_seen_at: None,
        },
    );
    plan_stall_exhausted(new_stall)
}

/// A bare continuation/approval message ("1", a step/option number, "ok"/"procedi"/
/// "continua"/"sì") is the user advancing an existing plan or approving a step — never
/// a fresh task. It must not trigger a one-shot workflow route (that's the APPROVAL-RESUME
/// dead-end). Kept deliberately tight (short, no task verbs) to avoid false positives.
fn is_plan_continuation_message(prompt: &str) -> bool {
    let t = prompt.trim().to_lowercase();
    if t.is_empty() || t.chars().count() > 16 {
        return false;
    }
    if t.chars().all(|c| c.is_ascii_digit()) {
        return true;
    }
    matches!(
        t.as_str(),
        "ok" | "okay"
            | "procedi"
            | "continua"
            | "prosegui"
            | "avanti"
            | "vai"
            | "sì"
            | "si"
            | "yes"
            | "y"
            | "go"
            | "next"
            | "continue"
    )
}

fn runtime_plan_step_outcome_matches(
    memory: &MemoryRecord,
    thread_key: &str,
    step_id: &str,
) -> bool {
    memory.memory_type == "fact"
        && !matches!(
            memory.status,
            MemoryStatus::Deleted | MemoryStatus::Rejected | MemoryStatus::Stale
        )
        && memory.metadata.get("source").and_then(|v| v.as_str()) == Some("runtime_plan_step")
        && memory.metadata.get("thread_id").and_then(|v| v.as_str()) == Some(thread_key)
        && memory.metadata.get("step_id").and_then(|v| v.as_str()) == Some(step_id)
}

fn record_runtime_plan_step_outcome(
    facade: &MemoryFacade,
    user: &MemoryUserId,
    workspace: &MemoryWorkspaceId,
    lifecycle: &MemoryLifecycleRequest,
    thread_id: Option<&str>,
    step: &serde_json::Value,
    evidence: &[String],
) -> Result<MemoryRef, String> {
    let thread_key = runtime_plan_thread_key(thread_id);
    let title = plan_step_title(step).trim();
    if title.is_empty() {
        return Err("runtime plan step outcome requires a title".to_string());
    }
    let step_id = plan_step_id(step).unwrap_or(title);
    let done_criterion = step
        .get("done_criterion")
        .and_then(|value| value.as_str())
        .unwrap_or("")
        .trim();
    let text = if done_criterion.is_empty() {
        format!("Runtime plan step completed: {title}.")
    } else {
        format!("Runtime plan step completed: {title}. Done criterion: {done_criterion}.")
    };
    let metadata = serde_json::json!({
        "source": "runtime_plan_step",
        "thread_id": thread_key,
        "execution_plan_ref": format!("runtime_plan:{thread_key}"),
        "step_id": step_id,
        "title": title,
        "status": "done",
        "done_criterion": done_criterion,
        "detail": step.get("detail").cloned().unwrap_or(serde_json::Value::Null),
        "evidence": evidence,
    });

    let existing = facade
        .list_memories_for_ui(user, workspace)
        .unwrap_or_default()
        .into_iter()
        .find(|memory| runtime_plan_step_outcome_matches(memory, &thread_key, step_id));

    let record = if let Some(existing) = existing {
        facade
            .update_memory(
                lifecycle,
                &existing.reference,
                MemoryUpdatePatch {
                    text: Some(text),
                    aliases: None,
                    language_hints: None,
                    confidence: Some(1.0),
                    privacy_domain: Some(PrivacyDomain::new("work")),
                    sensitivity: Some(MemoryDataSensitivity::Internal),
                    metadata: Some(metadata),
                    last_seen_at: None,
                },
            )
            .map_err(|error| error.to_string())?
    } else {
        facade
            .create_memory_candidate(MemoryCreateRequest {
                request: lifecycle.clone(),
                memory_type: "fact".to_string(),
                text,
                aliases: Vec::new(),
                language_hints: Vec::new(),
                confidence: 1.0,
                privacy_domain: PrivacyDomain::new("work"),
                sensitivity: MemoryDataSensitivity::Internal,
                evidence_refs: Vec::new(),
                metadata,
            })
            .map_err(|error| error.to_string())?
    };
    facade
        .confirm_memory(lifecycle, &record.reference, "runtime plan step verified")
        .map_err(|error| error.to_string())?;
    Ok(record.reference)
}

fn record_runtime_plan_step_outcome_from_state(
    state: &AppState,
    thread_id: Option<&str>,
    step: &serde_json::Value,
    evidence: &[String],
) {
    let Ok(facade) = lock_memory_facade(state) else {
        return;
    };
    let user = gateway_memory_user_id();
    let workspace = gateway_memory_workspace_id();
    let lifecycle = MemoryLifecycleRequest {
        actor_id: "runtime-plan".to_string(),
        user_id: user.clone(),
        workspace_id: workspace.clone(),
        purpose: "runtime_plan_step_verified".to_string(),
    };
    if record_runtime_plan_step_outcome(
        &facade, &user, &workspace, &lifecycle, thread_id, step, evidence,
    )
    .is_ok()
    {
        rebuild_status_wiki(&facade, &user, &workspace);
    }
}

fn record_subagent_task_step_outcome_memory(
    facade: &MemoryFacade,
    user: &MemoryUserId,
    workspace: &MemoryWorkspaceId,
    lifecycle: &MemoryLifecycleRequest,
    thread_id: Option<&str>,
    task: &TaskRecord,
    outcome: &TaskExecutionOutcome,
) -> Result<Option<MemoryRef>, String> {
    if !task.kind.starts_with("subagent.") || !outcome.completed {
        return Ok(None);
    }
    let title = task
        .input_json
        .get("goal")
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .unwrap_or(task.kind.as_str());
    let done_criterion = task
        .input_json
        .get("contract")
        .and_then(Value::as_str)
        .unwrap_or("sub-agent task completed");
    let step = serde_json::json!({
        "id": task.task_id.as_str(),
        "title": title,
        "status": "done",
        "detail": {
            "task_kind": task.kind.as_str(),
            "summary": outcome.summary,
        },
        "done_criterion": done_criterion,
    });
    let evidence = vec![
        serde_json::json!({
            "source": "subagent_task",
            "task_id": task.task_id.as_str(),
            "kind": task.kind.as_str(),
            "checkpoint": outcome.checkpoint_redacted,
        })
        .to_string(),
    ];
    record_runtime_plan_step_outcome(
        facade, user, workspace, lifecycle, thread_id, &step, &evidence,
    )
    .map(Some)
}

fn record_subagent_task_step_outcome(
    state: &AppState,
    task: &TaskRecord,
    outcome: &TaskExecutionOutcome,
) {
    let thread_id = lock_store(state)
        .ok()
        .and_then(|store| {
            store
                .thread_by_task_id(task.task_id.as_str())
                .ok()
                .flatten()
        })
        .map(|thread| thread.thread_id);
    let Ok(facade) = lock_memory_facade(state) else {
        return;
    };
    let user = gateway_memory_user_id();
    let workspace = gateway_memory_workspace_id();
    let lifecycle = MemoryLifecycleRequest {
        actor_id: "runtime-plan".to_string(),
        user_id: user.clone(),
        workspace_id: workspace.clone(),
        purpose: "subagent_plan_step_verified".to_string(),
    };
    if record_subagent_task_step_outcome_memory(
        &facade,
        &user,
        &workspace,
        &lifecycle,
        thread_id.as_deref(),
        task,
        outcome,
    )
    .is_ok()
    {
        rebuild_status_wiki(&facade, &user, &workspace);
    }
}

fn upsert_runtime_plan_graph(
    facade: &MemoryFacade,
    user: &MemoryUserId,
    workspace: &MemoryWorkspaceId,
    privacy_domain: &str,
    memory_ref: &MemoryRef,
    thread_key: &str,
    plan: &[serde_json::Value],
) -> Result<(), String> {
    let plan_key = format!("runtime_plan:{thread_key}");
    let plan_ref = MemoryRef::new(
        MemoryRefKind::Entity,
        user.clone(),
        workspace.clone(),
        plan_key.clone(),
    );
    facade
        .upsert_entity(&MemoryEntity {
            reference: plan_ref.clone(),
            user_id: user.clone(),
            workspace_id: workspace.clone(),
            entity_type: "document".to_string(),
            name: format!("Runtime plan {thread_key}"),
            canonical_key: plan_key,
            aliases: vec![thread_key.to_string()],
            privacy_domain: PrivacyDomain::new(privacy_domain),
            sensitivity: MemoryDataSensitivity::Internal,
            metadata: serde_json::json!({
                "source": "runtime_plan",
                "kind": "runtime_plan",
                "thread_id": thread_key,
                "status": if plan_is_complete(plan) { "complete" } else { "open" },
                "done_count": plan_done_count(plan),
                "total_count": plan.len(),
                "next_step": plan_next_open(plan),
                "execution_plan": runtime_execution_plan(plan),
            }),
        })
        .map_err(|error| error.to_string())?;
    upsert_memory_relation(
        facade,
        user,
        workspace,
        privacy_domain,
        format!(
            "runtime_plan_described_by:{}",
            provenance_key_fragment(thread_key)
        ),
        memory_ref.clone(),
        "describes",
        plan_ref.clone(),
        vec![memory_ref.clone()],
        serde_json::json!({
            "source": "runtime_plan",
            "thread_id": thread_key,
        }),
    )?;

    let step_refs: std::collections::HashMap<String, MemoryRef> = plan
        .iter()
        .filter_map(|step| {
            let id = plan_step_id(step)?;
            Some((
                id.to_string(),
                MemoryRef::new(
                    MemoryRefKind::Entity,
                    user.clone(),
                    workspace.clone(),
                    format!("runtime_plan:{thread_key}:step:{id}"),
                ),
            ))
        })
        .collect();

    for (index, step) in plan.iter().enumerate() {
        let Some(step_id) = plan_step_id(step) else {
            continue;
        };
        let step_ref = step_refs
            .get(step_id)
            .cloned()
            .expect("step ref built from same step id");
        let title = plan_step_title(step);
        facade
            .upsert_entity(&MemoryEntity {
                reference: step_ref.clone(),
                user_id: user.clone(),
                workspace_id: workspace.clone(),
                entity_type: "asset".to_string(),
                name: if title.is_empty() {
                    step_id.to_string()
                } else {
                    title.to_string()
                },
                canonical_key: format!("runtime_plan:{thread_key}:step:{step_id}"),
                aliases: vec![step_id.to_string()],
                privacy_domain: PrivacyDomain::new(privacy_domain),
                sensitivity: MemoryDataSensitivity::Internal,
                metadata: serde_json::json!({
                    "source": "runtime_plan",
                    "kind": "runtime_plan_step",
                    "thread_id": thread_key,
                    "step_id": step_id,
                    "index": index,
                    "title": title,
                    "status": plan_step_status(step),
                    "detail": step.get("detail").cloned().unwrap_or(serde_json::Value::Null),
                    "done_criterion": step.get("done_criterion").cloned().unwrap_or(serde_json::Value::Null),
                }),
            })
            .map_err(|error| error.to_string())?;
        upsert_memory_relation(
            facade,
            user,
            workspace,
            privacy_domain,
            format!(
                "runtime_plan_step:{}:{}",
                provenance_key_fragment(thread_key),
                provenance_key_fragment(step_id)
            ),
            plan_ref.clone(),
            "relates_to",
            step_ref.clone(),
            vec![memory_ref.clone()],
            serde_json::json!({
                "source": "runtime_plan",
                "kind": "has_step",
                "thread_id": thread_key,
                "step_id": step_id,
                "index": index,
            }),
        )?;

        let dependencies = plan_step_depends_on(step);
        for dependency_id in dependencies {
            let Some(dependency_ref) = step_refs.get(&dependency_id) else {
                continue;
            };
            upsert_memory_relation(
                facade,
                user,
                workspace,
                privacy_domain,
                format!(
                    "runtime_plan_step_depends:{}:{}:{}",
                    provenance_key_fragment(thread_key),
                    provenance_key_fragment(step_id),
                    provenance_key_fragment(&dependency_id)
                ),
                step_ref.clone(),
                "depends_on",
                dependency_ref.clone(),
                vec![memory_ref.clone()],
                serde_json::json!({
                    "source": "runtime_plan",
                    "thread_id": thread_key,
                    "step_id": step_id,
                    "depends_on": dependency_id,
                }),
            )?;
        }
    }
    Ok(())
}

fn upsert_runtime_plan_memory(
    facade: &MemoryFacade,
    user: &MemoryUserId,
    workspace: &MemoryWorkspaceId,
    lifecycle: &MemoryLifecycleRequest,
    thread_id: Option<&str>,
    plan: &[serde_json::Value],
) -> Result<Option<MemoryRef>, String> {
    let Some(text) = runtime_plan_memory_text(plan) else {
        return Ok(None);
    };
    let thread_key = runtime_plan_thread_key(thread_id);
    // Terminate (stop auto-resuming) when the plan is SETTLED — every step done OR blocked —
    // not only when fully complete. A blocked step is terminal: keeping such a plan "active"
    // is exactly the F4 infinite-resume loop. settled == complete when no step is blocked, so
    // this is behaviour-preserving for ordinary plans.
    let settled = plan_is_settled(plan);
    let mut metadata = runtime_plan_memory_metadata(thread_id, plan);
    let existing = facade
        .list_memories_for_ui(user, workspace)
        .unwrap_or_default()
        .into_iter()
        .find(|memory| runtime_plan_memory_matches(memory, &thread_key));

    match existing {
        Some(existing) => {
            // Carry the F4 cross-turn stall bookkeeping forward: it lives on the plan memory
            // but `runtime_plan_memory_metadata` rebuilds metadata from the steps alone, so a
            // mid-turn upsert would otherwise wipe the counter the turn-start guard wrote.
            if let Some(obj) = metadata.as_object_mut() {
                for key in ["stall_turns", "last_resume_done"] {
                    if let Some(value) = existing.metadata.get(key) {
                        obj.insert(key.to_string(), value.clone());
                    }
                }
            }
            let record = facade
                .update_memory(
                    lifecycle,
                    &existing.reference,
                    MemoryUpdatePatch {
                        text: Some(text),
                        aliases: None,
                        language_hints: None,
                        confidence: Some(1.0),
                        privacy_domain: Some(PrivacyDomain::new("work")),
                        sensitivity: Some(MemoryDataSensitivity::Internal),
                        metadata: Some(metadata),
                        last_seen_at: None,
                    },
                )
                .map_err(|error| error.to_string())?;
            if settled {
                facade
                    .mark_memory_stale(lifecycle, &record.reference, "runtime plan settled")
                    .map_err(|error| error.to_string())?;
            } else {
                facade
                    .confirm_memory(lifecycle, &record.reference, "runtime plan updated")
                    .map_err(|error| error.to_string())?;
            }
            upsert_runtime_plan_graph(
                facade,
                user,
                workspace,
                "work",
                &record.reference,
                &thread_key,
                plan,
            )?;
            Ok(Some(record.reference))
        }
        None if settled => Ok(None),
        None => {
            let record = facade
                .create_memory_candidate(MemoryCreateRequest {
                    request: lifecycle.clone(),
                    memory_type: "open_loop".to_string(),
                    text,
                    aliases: Vec::new(),
                    language_hints: Vec::new(),
                    confidence: 1.0,
                    privacy_domain: PrivacyDomain::new("work"),
                    sensitivity: MemoryDataSensitivity::Internal,
                    evidence_refs: Vec::new(),
                    metadata,
                })
                .map_err(|error| error.to_string())?;
            facade
                .confirm_memory(lifecycle, &record.reference, "runtime plan opened")
                .map_err(|error| error.to_string())?;
            upsert_runtime_plan_graph(
                facade,
                user,
                workspace,
                "work",
                &record.reference,
                &thread_key,
                plan,
            )?;
            Ok(Some(record.reference))
        }
    }
}

fn upsert_runtime_plan_memory_from_state(
    state: &AppState,
    thread_id: Option<&str>,
    plan: &[serde_json::Value],
) {
    let Ok(facade) = lock_memory_facade(state) else {
        return;
    };
    let user = gateway_memory_user_id();
    let workspace = gateway_memory_workspace_id();
    let lifecycle = MemoryLifecycleRequest {
        actor_id: "runtime-plan".to_string(),
        user_id: user.clone(),
        workspace_id: workspace.clone(),
        purpose: "sync_runtime_plan".to_string(),
    };
    if upsert_runtime_plan_memory(&facade, &user, &workspace, &lifecycle, thread_id, plan).is_ok() {
        rebuild_status_wiki(&facade, &user, &workspace);
    }
}

/// Merge the model's sent steps into the CANONICAL plan (never replace). Match an
/// existing step by title (case-insensitive): a canonical `done` is STICKY — re-sending
/// it as todo/doing can't reopen it (this is what stops the regenerate loop); a NEW
/// `done` claim is held as `doing` and its index returned (pending F2 verification); a
/// new title is appended with a stable id. Returns the canonical indices newly claimed.
fn merge_plan(plan: &mut Vec<serde_json::Value>, sent: &[serde_json::Value]) -> Vec<usize> {
    let tkey = |t: &str| t.trim().to_lowercase();
    let mut claims: Vec<usize> = Vec::new();
    for s in sent {
        let title = s.get("title").and_then(|v| v.as_str()).unwrap_or("").trim();
        // Identity: prefer the stable `id` the model echoes (shown as (`id`) in the
        // ‹‹PLAN›› marker); fall back to title. Id-first stops ballooning from
        // paraphrased titles, AND lets `step_advance` update a step by id ALONE (no
        // title) — the model reports progress without re-sending the whole plan. (WS1-F2.)
        let sent_id = s
            .get("id")
            .and_then(|v| v.as_str())
            .map(str::trim)
            .filter(|x| !x.is_empty());
        if title.is_empty() && sent_id.is_none() {
            continue;
        }
        let new_status = s.get("status").and_then(|v| v.as_str()).unwrap_or("todo");
        let detail = s.get("detail").and_then(|v| v.as_str()).unwrap_or("");
        let pos = sent_id
            .and_then(|id| {
                plan.iter()
                    .position(|p| p.get("id").and_then(|v| v.as_str()) == Some(id))
            })
            .or_else(|| {
                if title.is_empty() {
                    None
                } else {
                    plan.iter()
                        .position(|p| tkey(plan_step_title(p)) == tkey(title))
                }
            });
        match pos {
            Some(i) => {
                if matches!(plan_step_status(&plan[i]), "done" | "blocked") {
                    // sticky: a `done` step never re-opens (stops the regenerate loop), and a
                    // `blocked` step stays blocked — the harness blocks a stalled step (F4) and
                    // the model must not re-open it, which would re-arm the cross-turn loop.
                } else if new_status == "done" {
                    plan[i]["status"] = serde_json::json!("doing");
                    claims.push(i);
                } else {
                    plan[i]["status"] = serde_json::json!(new_status);
                }
                if !detail.is_empty() {
                    plan[i]["detail"] = serde_json::json!(detail);
                }
                let depends_on = plan_step_depends_on(s);
                if !depends_on.is_empty() {
                    plan[i]["depends_on"] = serde_json::json!(depends_on);
                }
            }
            None => {
                if title.is_empty() {
                    // id-only update (step_advance) for a step that doesn't exist →
                    // ignore; we never create a titleless step.
                    continue;
                }
                let id = format!("s{}", plan.len() + 1);
                let status = if new_status == "done" {
                    "doing"
                } else {
                    new_status
                };
                plan.push(serde_json::json!({
                    "id": id, "title": title, "status": status, "detail": detail,
                    "done_criterion": s.get("done_criterion").and_then(|v| v.as_str()).unwrap_or(""),
                    "depends_on": plan_step_depends_on(s),
                }));
                if new_status == "done" {
                    claims.push(plan.len() - 1);
                }
            }
        }
    }
    claims
}

/// Formats the agent's plan steps into the exact Markdown the Workbench "Piano" panel
/// parses (`- [m] **Title** (\`id\`): detail`).
/// Read-only query over the active project's CODE graph (imported by the project-map
/// builder). Answers "what calls X / what does X call / where does X live" by
/// traversing the calls/contains/method edges already in SQLite — no Graphify needed.
fn query_code_graph_tool_schema() -> serde_json::Value {
    serde_json::json!({
        "type": "function",
        "function": {
            "name": "query_code_graph",
            "description": "Query the code map of the active project: given a symbol (function, file, \
    class), list who calls it, what it calls and where it's located. Use it for questions about the \
    architecture/structure of the current project's code.",
            "parameters": {
                "type": "object",
                "properties": {
                    "symbol": { "type": "string", "description": "Name of the symbol to explore (e.g. \"cmd_add\", \"main.py\")" }
                },
                "required": ["symbol"]
            }
        }
    })
}

/// Read-only query over the active project's GIT HISTORY — the "why over time" leg of
/// memory. Commit messages = the why; `-S` (pickaxe) = when code containing a term
/// changed. Complements query_code_graph (current structure) and the decision wiki
/// (conversational why). No writes.
fn query_git_history_tool_schema() -> serde_json::Value {
    serde_json::json!({
        "type": "function",
        "function": {
            "name": "query_git_history",
            "description": "Query the git HISTORY of the active project: given a file, a symbol, or a \
    theme, returns the relevant commits (message = the WHY, with date) and when the related \
    code changed. Use it for 'why/when did X change', 'the history of Y', 'what \
    happened to this file'.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": { "type": "string", "description": "File, symbol or theme (e.g. \"trello_wrapper.py\", \"retry\", \"cache\")" }
                },
                "required": ["query"]
            }
        }
    })
}

fn github_search_tool_schema() -> serde_json::Value {
    serde_json::json!({
        "type": "function",
        "function": {
            "name": "github_search",
            "description": "Search REPOSITORIES on GitHub via API (fast and structured, NO browser). \
    Use it for \"search GitHub\", finding similar/competing projects, assessing the uniqueness of an idea, or \
    inspecting repos for stars/language/freshness. Returns the top repos sorted by stars. \
    ALWAYS PREFER it over the browser for GitHub queries.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": { "type": "string", "description": "Search terms (name, problem/implementation keyword). Supports GitHub qualifiers, e.g. \"todo cli language:python stars:>50\"." }
                },
                "required": ["query"]
            }
        }
    })
}

/// Searches GitHub repositories via the public Search API (no auth needed for public repos;
/// fast + structured — the model should prefer this over driving the browser).
async fn github_search(state: &AppState, query: &str) -> String {
    let resp = state
        .http
        .get("https://api.github.com/search/repositories")
        .query(&[
            ("q", query),
            ("sort", "stars"),
            ("order", "desc"),
            ("per_page", "8"),
        ])
        .header("User-Agent", "Homun")
        .header("Accept", "application/vnd.github+json")
        .timeout(std::time::Duration::from_secs(20))
        .send()
        .await;
    let resp = match resp {
        Ok(r) if r.status().is_success() => r,
        Ok(r) => return format!("GitHub search failed (HTTP {}).", r.status()),
        Err(_) => return "GitHub search failed (network).".to_string(),
    };
    let Ok(json) = resp.json::<serde_json::Value>().await else {
        return "Unreadable GitHub response.".to_string();
    };
    let items = json
        .get("items")
        .and_then(|v| v.as_array())
        .cloned()
        .unwrap_or_default();
    if items.is_empty() {
        return format!("No repository found on GitHub for «{query}».");
    }
    let mut out = format!("GitHub results for «{query}» (top by stars):");
    for it in items.iter().take(8) {
        let name = it.get("full_name").and_then(|v| v.as_str()).unwrap_or("?");
        let stars = it
            .get("stargazers_count")
            .and_then(|v| v.as_u64())
            .unwrap_or(0);
        let lang = it.get("language").and_then(|v| v.as_str()).unwrap_or("—");
        let desc = it.get("description").and_then(|v| v.as_str()).unwrap_or("");
        let url = it.get("html_url").and_then(|v| v.as_str()).unwrap_or("");
        let pushed = it.get("pushed_at").and_then(|v| v.as_str()).unwrap_or("");
        let desc_short: String = desc.chars().take(140).collect();
        out.push_str(&format!(
            "\n- {name} ⭐{stars} [{lang}] — {desc_short}\n  {url}  (aggiornato {})",
            pushed.get(0..10).unwrap_or(pushed)
        ));
    }
    out
}

fn query_git_history(query: &str) -> String {
    let q = query.trim();
    if q.is_empty() {
        return "Indicate a file, symbol or topic.".to_string();
    }
    let ws = gateway_memory_workspace_id();
    let folder = load_workspaces_file()
        .workspaces
        .into_iter()
        .find(|w| w.id == ws.as_str())
        .and_then(|w| w.folder)
        .filter(|f| !f.trim().is_empty());
    let Some(folder) = folder else {
        return "This scope is not a project with a folder.".to_string();
    };
    let root = std::path::Path::new(&folder);
    let is_git = std::process::Command::new("git")
        .arg("-C")
        .arg(root)
        .args(["rev-parse", "--is-inside-work-tree"])
        .output()
        .map(|o| o.status.success())
        .unwrap_or(false);
    if !is_git {
        return "This project isn't under git yet (no history to consult).".to_string();
    }
    let run = |args: &[&str]| -> String {
        std::process::Command::new("git")
            .arg("-C")
            .arg(root)
            .args(args)
            .output()
            .ok()
            .filter(|o| o.status.success())
            .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
            .unwrap_or_default()
    };
    let fmt = "--pretty=format:%h %ad %s";
    let date = "--date=short";
    // Commit MESSAGES mentioning the term (the explicit "why").
    let by_msg = run(&["log", fmt, date, "-n", "10", "-i", &format!("--grep={q}")]);
    // Commits that CHANGED code containing the term (pickaxe: when X appeared/changed).
    let by_code = run(&["log", fmt, date, "-n", "10", &format!("-S{q}")]);
    // If the query is (or matches) a path, its file history too.
    let by_path = if q.contains('.') || q.contains('/') {
        run(&["log", fmt, date, "-n", "10", "--", &format!("*{q}*")])
    } else {
        String::new()
    };
    if by_msg.is_empty() && by_code.is_empty() && by_path.is_empty() {
        return format!("No commit found for «{q}» (maybe it's code not yet committed).");
    }
    let mut out = format!("Git history for «{q}»:\n");
    if !by_msg.is_empty() {
        out.push_str(&format!("\n**Commits that mention it (why):**\n{by_msg}\n"));
    }
    if !by_path.is_empty() {
        out.push_str(&format!("\n**File history:**\n{by_path}\n"));
    }
    if !by_code.is_empty() {
        out.push_str(&format!(
            "\n**When the code with «{q}» changed:**\n{by_code}\n"
        ));
    }
    out
}

fn query_code_graph(state: &AppState, symbol: &str) -> String {
    let needle = symbol.trim().to_lowercase();
    if needle.is_empty() {
        return "Specify a symbol (function/file) to explore.".to_string();
    }
    let Ok(facade) = lock_memory_facade(state) else {
        return "Memory unavailable.".to_string();
    };
    let user = gateway_memory_user_id();
    let ws = gateway_memory_workspace_id();
    let entities = facade.list_entities_for_ui(&user, &ws).unwrap_or_default();
    // Only the code graph (entities imported from the project map).
    let code: Vec<_> = entities
        .iter()
        .filter(|e| e.entity_type.starts_with("code_"))
        .collect();
    if code.is_empty() {
        return "There's no code map for this project yet.".to_string();
    }
    let Some(target) = code
        .iter()
        .find(|e| e.name.to_lowercase() == needle)
        .or_else(|| {
            code.iter()
                .find(|e| e.name.to_lowercase().contains(&needle))
        })
    else {
        return format!("I can't find «{symbol}» in the project's code map.");
    };
    let tref = target.reference.to_string();
    let name_by_ref: std::collections::HashMap<String, String> = entities
        .iter()
        .map(|e| (e.reference.to_string(), e.name.clone()))
        .collect();
    let rels = facade.list_relations_for_ui(&user, &ws).unwrap_or_default();
    let mut calls: Vec<String> = Vec::new(); // target → X (outgoing)
    let mut callers: Vec<String> = Vec::new(); // X → target (incoming)
    let mut container: Option<String> = None;
    for r in &rels {
        let s = r.source_ref.to_string();
        let t = r.target_ref.to_string();
        if s == tref {
            if r.relation_type == "contains" {
                continue; // target contains children — list as calls below if relevant
            }
            if let Some(n) = name_by_ref.get(&t) {
                calls.push(n.clone());
            }
        } else if t == tref {
            if r.relation_type == "contains" {
                container = name_by_ref.get(&s).cloned();
            } else if let Some(n) = name_by_ref.get(&s) {
                callers.push(n.clone());
            }
        }
    }
    calls.sort();
    calls.dedup();
    calls.truncate(20);
    callers.sort();
    callers.dedup();
    callers.truncate(20);
    let mut out = format!("**{}**", target.name);
    if let Some(c) = container {
        out.push_str(&format!(" (in {c})"));
    }
    out.push('\n');
    if callers.is_empty() {
        out.push_str("- No known callers.\n");
    } else {
        out.push_str(&format!("- Called by: {}\n", callers.join(", ")));
    }
    if !calls.is_empty() {
        out.push_str(&format!("- Uses/calls: {}\n", calls.join(", ")));
    }
    out
}

fn resolve_datetime_tool_schema() -> serde_json::Value {
    serde_json::json!({
        "type": "function",
        "function": {
            "name": "resolve_datetime",
            "description": "Converts a user's time reference (in ANY language: \"tomorrow morning\", \
    \"next Monday at 9\", \"pasado mañana\", \"in 3 days\", \"the 15th\") into the correct ABSOLUTE \
    date/time, computed relative to NOW and the user's timezone. CALL IT BEFORE using any date — don't \
    compute dates yourself (you easily get \"today\" wrong). You CLASSIFY the reference by filling in the \
    fields below; I do the computation. Returns the ISO value to write into forms or pass to other tools.",
            "parameters": {
                "type": "object",
                "properties": {
                    "kind": {
                        "type": "string",
                        "enum": ["relative_day", "weekday", "relative_unit", "absolute"],
                        "description": "relative_day: today/tomorrow/yesterday/day-after-tomorrow (use offset_days). \
    weekday: a day of the week (use weekday + which). relative_unit: \"in N days/weeks/months\" \
    (use n + unit). absolute: explicit date (use date)."
                    },
                    "offset_days": {
                        "type": "integer",
                        "description": "For kind=relative_day: 0=today, 1=tomorrow, -1=yesterday, 2=day-after-tomorrow, etc."
                    },
                    "weekday": {
                        "type": "string",
                        "description": "For kind=weekday: monday..sunday (or monday..sunday, any language)."
                    },
                    "which": {
                        "type": "string",
                        "enum": ["upcoming", "this", "next"],
                        "description": "For kind=weekday: upcoming=the closest future (default), this=this week, next=next week."
                    },
                    "n": { "type": "integer", "description": "For kind=relative_unit: how many units (e.g. 3)." },
                    "unit": {
                        "type": "string",
                        "enum": ["day", "week", "month"],
                        "description": "For kind=relative_unit: the unit (day/week/month)."
                    },
                    "date": { "type": "string", "description": "For kind=absolute: ISO date YYYY-MM-DD." },
                    "time": { "type": "string", "description": "Time \"HH:MM\" if the user specifies it (e.g. \"07:00\"). Optional." },
                    "part": {
                        "type": "string",
                        "enum": ["morning", "afternoon", "evening", "night"],
                        "description": "Part of day if there's no precise time (e.g. \"in the morning\"). Optional."
                    },
                    "must_be_future": {
                        "type": "boolean",
                        "description": "Default true: rejects an already-past date/time (for bookings/searches). Set false only if a past date is needed."
                    }
                },
                "required": ["kind"]
            }
        }
    })
}

