/// Human label for a recurrence rule (handles the flexible `dow@days@times` form).
fn humanize_recurrence(rec: &str) -> String {
    fn day_label(d: &str) -> &str {
        match d.trim() {
            "mon" => "Mon",
            "tue" => "Tue",
            "wed" => "Wed",
            "thu" => "Thu",
            "fri" => "Fri",
            "sat" => "Sat",
            "sun" => "Sun",
            other => other,
        }
    }
    let lower = rec.trim().to_ascii_lowercase();
    if let Some(rest) = lower.strip_prefix("dow") {
        if let Some((days, times)) = rest.trim_start_matches(['@', ' ']).split_once('@') {
            let times_h = times
                .split(',')
                .map(str::trim)
                .collect::<Vec<_>>()
                .join(", ");
            let days_h = if matches!(days.trim(), "*" | "all" | "daily" | "") {
                "Every day".to_string()
            } else {
                days.split(',')
                    .map(day_label)
                    .collect::<Vec<_>>()
                    .join(", ")
            };
            return format!("{days_h} · {times_h}");
        }
    }
    if let Some(t) = lower.strip_prefix("daily") {
        return format!("Every day · {}", t.trim_start_matches(['@', ' ']).trim());
    }
    if let Some(rest) = lower.strip_prefix("weekly") {
        let rest = rest.trim_start_matches(['@', ' ']);
        if let Some((d, t)) = rest.split_once(['@', ' ']) {
            return format!(
                "{} · {}",
                day_label(d),
                t.trim_start_matches(['@', ' ']).trim()
            );
        }
    }
    if lower.starts_with("every") {
        return rec.replacen("every", "Every", 1);
    }
    rec.to_string()
}

/// Human one-line summary of a trigger for the list view.
fn automation_trigger_summary(trigger: &AutomationTrigger) -> String {
    match trigger {
        AutomationTrigger::Schedule { recurrence, .. } => {
            format!("Schedule · {}", humanize_recurrence(recurrence))
        }
        AutomationTrigger::Event { event } => match event {
            EventTrigger::ChannelMessage { channel, from } => {
                let ch = channel.as_deref().unwrap_or("any channel");
                match from {
                    Some(f) => format!("When {f} writes on {ch}"),
                    None => format!("Message on {ch}"),
                }
            }
            EventTrigger::EmailReceived { from } => match from {
                Some(f) => format!("Email from {f}"),
                None => "Email received".to_string(),
            },
            EventTrigger::FileChanged { path } => format!("File changed: {path}"),
            EventTrigger::MemoryUpdated { topic } => match topic {
                Some(t) => format!("Memory updated: {t}"),
                None => "Memory updated".to_string(),
            },
            EventTrigger::ConnectorPoll { tool, label, .. } => match label {
                Some(l) => format!("Event · {l}"),
                None => format!("Event · {tool}"),
            },
        },
    }
}

/// Clean UI-facing DTO: unix-second timestamps (the `time` crate's default serde is a numeric
/// array — useless for the frontend), a human trigger summary, and next_run for schedules.
/// `trigger` stays a typed object so the editor can round-trip it.
fn automation_to_json(a: &Automation) -> serde_json::Value {
    let next_run = match &a.trigger {
        AutomationTrigger::Schedule { recurrence, tz } if a.enabled => {
            local_first_task_runtime::next_occurrence(
                recurrence,
                tz.as_deref(),
                OffsetDateTime::now_utc(),
            )
            .map(|t| t.unix_timestamp())
        }
        _ => None,
    };
    serde_json::json!({
        "id": a.id,
        "title": a.title,
        "trigger": a.trigger,
        "trigger_summary": automation_trigger_summary(&a.trigger),
        "prompt": a.prompt,
        "approval": a.approval,
        "enabled": a.enabled,
        "source": a.source,
        "task_id": a.task_id,
        "created_at": a.created_at.unix_timestamp(),
        "updated_at": a.updated_at.unix_timestamp(),
        "last_fired_at": a.last_fired_at.map(|t| t.unix_timestamp()),
        "next_run": next_run,
    })
}

/// For a Schedule automation, create the recurring TaskRecord that DRIVES it and return its
/// id (tagged with `automation_id` so the run + queue can trace it back). Event automations
/// return `None` — their runs are materialized when the event fires (Auto-C). Validates the
/// recurrence (so an invalid rule fails here, not silently at run time).
fn materialize_automation_task(
    store: &TaskStore,
    automation: &Automation,
) -> Result<Option<String>, String> {
    let (recurrence, tz) = match &automation.trigger {
        AutomationTrigger::Schedule { recurrence, tz } => (recurrence.clone(), tz.clone()),
        AutomationTrigger::Event { .. } => return Ok(None),
    };
    let now = OffsetDateTime::now_utc();
    let next = local_first_task_runtime::next_occurrence(&recurrence, tz.as_deref(), now)
        .ok_or_else(|| format!("recurrence '{recurrence}' is not valid"))?;
    let task_id = format!("autorun_{}", uuid::Uuid::new_v4().simple());
    let mut task = TaskRecord::new(
        task_id.clone(),
        automation.user_id.clone(),
        automation.workspace_id.clone(),
        "proactive_prompt",
        automation.prompt.clone(),
        serde_json::json!({ "automation_id": automation.id, "approval": automation.approval }),
    );
    task.not_before = Some(next);
    task.recurrence = Some(recurrence);
    task.recurrence_tz = tz;
    // Transient failures (a flaky site, a momentary network blip) shouldn't drop a
    // run: retry a few times with backoff before the occurrence is considered failed.
    // next_recurrence carries this policy onto every following occurrence.
    task.retry_policy = local_first_task_runtime::RetryPolicy {
        max_attempts: 3,
        backoff_seconds: 120,
    };
    store.insert_task(&task).map_err(|e| e.to_string())?;
    Ok(Some(task_id))
}

/// Stop an automation's driving task (cancel all future occurrences). Best-effort.
fn cancel_automation_task(store: &TaskStore, task_id: &str) {
    let _ = store.update_task_status(
        &local_first_task_runtime::TaskId::new(task_id),
        &gateway_user_id(),
        &gateway_workspace_id(),
        TaskStatus::Cancelled,
        Some("automation disabled or deleted"),
    );
}

