async fn template_catalog() -> Json<TemplateCatalogResponse> {
    Json(template_catalog_response_from_entries(
        template_catalog_entries(),
    ))
}

async fn template_preview(
    Query(query): Query<TemplatePreviewQuery>,
) -> Result<Response, GatewayError> {
    let reference = query.reference.trim();
    let rest = reference
        .strip_prefix("template-pack://")
        .ok_or_else(|| GatewayError {
            status: StatusCode::BAD_REQUEST,
            code: "template_preview_ref_invalid",
            message: "Template preview reference is invalid.".to_string(),
        })?;

    for entry in template_catalog_entries() {
        let Some(pack_root) = entry.template_pack_root.as_ref() else {
            continue;
        };
        let Some(internal_preview) = entry.preview_ref.as_deref() else {
            continue;
        };
        if internal_preview != reference {
            continue;
        }
        let prefix = format!("{}/", entry.id);
        let Some(relative_path) = rest.strip_prefix(&prefix) else {
            continue;
        };
        if !relative_path.starts_with("thumbnails/") || !relative_path.ends_with(".png") {
            return Err(GatewayError {
                status: StatusCode::BAD_REQUEST,
                code: "template_preview_path_invalid",
                message: "Template preview path is invalid.".to_string(),
            });
        }
        let path = jail_in_root(pack_root, relative_path).map_err(|message| GatewayError {
            status: StatusCode::BAD_REQUEST,
            code: "template_preview_path_invalid",
            message,
        })?;
        if !path.is_file() {
            return Err(GatewayError {
                status: StatusCode::NOT_FOUND,
                code: "template_preview_missing",
                message: "Template preview image is missing.".to_string(),
            });
        }
        let bytes = fs::read(&path).map_err(|error| GatewayError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            code: "template_preview_read_failed",
            message: error.to_string(),
        })?;
        return Response::builder()
            .header(CONTENT_TYPE, "image/png")
            .body(Body::from(bytes))
            .map_err(|error| GatewayError {
                status: StatusCode::INTERNAL_SERVER_ERROR,
                code: "template_preview_response_failed",
                message: error.to_string(),
            });
    }

    Err(GatewayError {
        status: StatusCode::NOT_FOUND,
        code: "template_preview_not_found",
        message: "Template preview was not found.".to_string(),
    })
}

async fn import_pptx_template(
    Json(request): Json<ImportPptxTemplateRequest>,
) -> Result<Json<TemplateCatalogEntryResponse>, GatewayError> {
    let root = imported_template_pack_root().ok_or_else(|| GatewayError {
        status: StatusCode::INTERNAL_SERVER_ERROR,
        code: "template_pack_root_unavailable",
        message: "Template pack root is unavailable.".to_string(),
    })?;
    let entry = import_pptx_template_pack(&root, request).map_err(|message| GatewayError {
        status: StatusCode::BAD_REQUEST,
        code: "template_import_failed",
        message,
    })?;
    let mut response = template_catalog_response_from_entries(vec![entry]);
    let entry = response.templates.pop().ok_or_else(|| GatewayError {
        status: StatusCode::INTERNAL_SERVER_ERROR,
        code: "template_import_empty_response",
        message: "Imported template response is empty.".to_string(),
    })?;
    Ok(Json(entry))
}

async fn delete_template(
    Json(request): Json<TemplateDeleteRequest>,
) -> Result<Json<TemplateCatalogResponse>, GatewayError> {
    let root = imported_template_pack_root().ok_or_else(|| GatewayError {
        status: StatusCode::INTERNAL_SERVER_ERROR,
        code: "template_pack_root_unavailable",
        message: "Template pack root is unavailable.".to_string(),
    })?;
    delete_imported_template_pack(&root, &request.template_id).map_err(|message| GatewayError {
        status: StatusCode::BAD_REQUEST,
        code: "template_delete_failed",
        message,
    })?;
    Ok(Json(template_catalog_response_from_entries(
        template_catalog_entries(),
    )))
}

async fn template_source_attachment(
    Json(request): Json<TemplateSourceAttachmentRequest>,
) -> Result<Json<TemplateSourceAttachmentResponse>, GatewayError> {
    let entry = template_catalog_by_id(Some(&request.template_id)).ok_or_else(|| GatewayError {
        status: StatusCode::NOT_FOUND,
        code: "template_not_found",
        message: "Template was not found in the catalog.".to_string(),
    })?;
    let source_path = entry.source_path.ok_or_else(|| GatewayError {
        status: StatusCode::BAD_REQUEST,
        code: "template_source_unavailable",
        message: "This template does not expose a local source file.".to_string(),
    })?;
    if !source_path.is_file() {
        return Err(GatewayError {
            status: StatusCode::NOT_FOUND,
            code: "template_source_missing",
            message: "The imported template source file is missing.".to_string(),
        });
    }
    let extension = source_path
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or("pptx")
        .to_ascii_lowercase();
    let mime_type = if extension == "potx" {
        "application/vnd.openxmlformats-officedocument.presentationml.template"
    } else {
        "application/vnd.openxmlformats-officedocument.presentationml.presentation"
    };
    let size_bytes = source_path
        .metadata()
        .map(|metadata| metadata.len())
        .unwrap_or(0);
    let display_slug = slugify_template_pack_name(&entry.name).unwrap_or_else(|| "template".into());
    Ok(Json(TemplateSourceAttachmentResponse {
        local_path: source_path.to_string_lossy().to_string(),
        display_name: format!("{display_slug}.{extension}"),
        mime_type: mime_type.to_string(),
        size_bytes,
    }))
}

fn task_queue_response_for_state(state: &AppState) -> Result<TaskQueueResponse, GatewayError> {
    let user = gateway_user_id();
    let workspace = gateway_workspace_id();
    let store = lock_task_store(state)?;
    let snapshot = TaskUiReadModel::new(&store)
        .queue_snapshot(&user, &workspace)
        .map_err(GatewayError::task)?;
    let limits = effective_task_resource_limits();
    task_queue_response(snapshot, &limits)
}

fn task_queue_response(
    snapshot: TaskQueueSnapshot,
    limits: &ResourceLimits,
) -> Result<TaskQueueResponse, GatewayError> {
    let mut resource_usage = snapshot
        .resource_usage
        .into_iter()
        .map(|(resource_class, units)| {
            let limit = limits.limit_for(resource_class);
            ResourceUsageResponse {
                resource_class: resource_class_label(resource_class).to_string(),
                units,
                limit_units: limit,
                available_units: limit.map(|limit| limit.saturating_sub(units)),
                saturated: limit.is_some_and(|limit| units >= limit),
            }
        })
        .collect::<Vec<_>>();
    resource_usage.sort_by(|left, right| left.resource_class.cmp(&right.resource_class));

    // The queue lists USER-meaningful runs (automations, proactive prompts). Internal
    // execution sub-tasks (capability.* / subagent.*) are filtered out — they belong to
    // the Computer/activity view, not the queue. This is the fix for the "browser noise".
    let user_facing = |items: Vec<TaskUiItem>| {
        items
            .into_iter()
            .filter(|i| !is_internal_task_kind(&i.kind))
            .map(task_item_response)
            .collect::<Result<Vec<_>, _>>()
    };
    Ok(TaskQueueResponse {
        queued: user_facing(snapshot.queued)?,
        active: user_facing(snapshot.active)?,
        blocked: user_facing(snapshot.blocked)?,
        waiting_approvals: snapshot
            .waiting_approvals
            .into_iter()
            .map(approval_item_response)
            .collect::<Result<Vec<_>, _>>()?,
        recent_failures: user_facing(snapshot.recent_failures)?,
        resource_usage,
    })
}

fn task_detail_response(detail: TaskUiDetail) -> Result<TaskDetailResponse, GatewayError> {
    Ok(TaskDetailResponse {
        item: task_item_response(TaskUiItem {
            task_id: detail.task_id,
            kind: detail.kind,
            goal: detail.goal,
            status: detail.status,
            priority: detail.priority,
            blocked_reason: detail.blocked_reason,
        })?,
        latest_checkpoint: detail.latest_checkpoint,
        runtime_metadata: detail.runtime_metadata,
        exposes_raw_input: detail.exposes_raw_input,
    })
}

/// Execution sub-tasks the user shouldn't see in the queue — internal steps of a run
/// (capability calls, subagent workflows). They surface in the Computer/activity view, not
/// in the user-facing queue (which lists automations runs + proactive prompts).
fn is_internal_task_kind(kind: &str) -> bool {
    kind.starts_with("capability.") || kind.starts_with("subagent.")
}

/// Human label for a task kind shown in the queue.
fn humanize_task_kind(kind: &str) -> String {
    let cap = |s: &str| {
        let mut chars = s.chars();
        chars
            .next()
            .map(|f| f.to_uppercase().collect::<String>() + chars.as_str())
            .unwrap_or_default()
    };
    match kind {
        "proactive_prompt" => "Automation".to_string(),
        other if other.starts_with("capability.") => {
            let rest = other.trim_start_matches("capability.");
            let mut parts = rest.splitn(2, '.');
            let provider = parts.next().unwrap_or(rest);
            let tool = parts.next().unwrap_or("");
            if tool.is_empty() {
                cap(provider)
            } else {
                format!("{}: {}", cap(provider), tool.replace('_', " "))
            }
        }
        other if other.starts_with("subagent.") => {
            format!("Sub-agent: {}", other.trim_start_matches("subagent."))
        }
        other => cap(&other.replace('_', " ")),
    }
}

fn task_item_response(item: TaskUiItem) -> Result<TaskItemResponse, GatewayError> {
    Ok(TaskItemResponse {
        task_id: item.task_id.as_str().to_string(),
        label: humanize_task_kind(&item.kind),
        kind: item.kind,
        goal: item.goal,
        status: enum_label(&item.status)?,
        priority: enum_label(&item.priority)?,
        blocked_reason: item.blocked_reason,
    })
}

fn approval_item_response(approval: ApprovalRequest) -> Result<ApprovalItemResponse, GatewayError> {
    let browser_scoped = approval.action == "browser.manual_action"
        || approval.action == "prompt_plan.approve_step"
        || approval.data_boundary.contains("browser")
        || approval.explanation.to_lowercase().contains("browser");
    Ok(ApprovalItemResponse {
        approval_id: approval.approval_id,
        task_id: approval.task_id.as_str().to_string(),
        action: approval.action,
        risk_level: approval.risk_level,
        data_boundary: approval.data_boundary,
        explanation: approval.explanation,
        status: enum_label(&approval.status)?,
        scope_options: if browser_scoped {
            vec!["once".to_string(), "always".to_string()]
        } else {
            vec!["once".to_string()]
        },
        browser_visibility_options: if browser_scoped {
            vec![
                "auto".to_string(),
                "visible".to_string(),
                "headless".to_string(),
            ]
        } else {
            Vec::new()
        },
        default_browser_visibility: "auto".to_string(),
    })
}

fn ensure_computer_session_for_task(
    state: &AppState,
    session_id: &str,
    task_id: &str,
    thread_id: &str,
    goal_redacted: &str,
    requires_approval: bool,
) -> Result<(), GatewayError> {
    let user = gateway_user_id();
    let workspace = gateway_workspace_id();
    let mut store = lock_computer_store(state)?;
    if store
        .session(session_id, user.as_str(), workspace.as_str())
        .map_err(GatewayError::local_computer)?
        .is_some()
    {
        return Ok(());
    }

    let now = OffsetDateTime::now_utc();
    let session = ComputerSessionRecord {
        session_id: session_id.to_string(),
        task_id: task_id.to_string(),
        workflow_id: Some(format!("workflow_{thread_id}")),
        user_id: user.as_str().to_string(),
        workspace_id: workspace.as_str().to_string(),
        status: if requires_approval {
            SessionStatus::WaitingUser
        } else {
            SessionStatus::Running
        },
        active_surface: if goal_redacted.to_lowercase().contains("terminal") {
            SurfaceKind::Shell
        } else {
            SurfaceKind::Browser
        },
        surfaces: default_computer_surfaces(now),
        title: "Computer locale".to_string(),
        subtitle: goal_redacted.to_string(),
        progress_current: 0,
        progress_total: if requires_approval { 3 } else { 2 },
        approval_state: if requires_approval {
            ApprovalState::WaitingUser
        } else {
            ApprovalState::None
        },
        takeover_state: TakeoverState::None,
        risk_level: if requires_approval { "medium" } else { "low" }.to_string(),
        last_error: None,
        started_at: now,
        updated_at: now,
    };
    store
        .upsert_session(&session)
        .map_err(GatewayError::local_computer)?;
    append_computer_event(
        &mut store,
        session_id,
        &user,
        &workspace,
        SurfaceKind::Logs,
        "computer_session_started",
        "done",
        "Local task created",
        "Local Computer session associated with the chat.",
        false,
    )?;
    if requires_approval {
        append_computer_event(
            &mut store,
            session_id,
            &user,
            &workspace,
            SurfaceKind::Logs,
            "computer_approval_required",
            "waiting",
            "Approval required",
            "Confirm the plan before running local actions.",
            true,
        )?;
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn append_computer_event(
    store: &mut LocalComputerSessionStore,
    session_id: &str,
    user: &UserId,
    workspace: &WorkspaceId,
    surface: SurfaceKind,
    kind: &str,
    status: &str,
    title: &str,
    subtitle: &str,
    approval_required: bool,
) -> Result<(), GatewayError> {
    store
        .append_event(&ComputerEventRecord {
            event_id: format!(
                "event_{}_{}",
                OffsetDateTime::now_utc().unix_timestamp_nanos(),
                kind
            ),
            session_id: session_id.to_string(),
            user_id: user.as_str().to_string(),
            workspace_id: workspace.as_str().to_string(),
            surface,
            kind: kind.to_string(),
            status: status.to_string(),
            title: title.to_string(),
            subtitle: subtitle.to_string(),
            payload: serde_json::json!({ "payload_redacted": true }),
            artifact_refs: vec![],
            approval_required,
            created_at: OffsetDateTime::now_utc(),
        })
        .map_err(GatewayError::local_computer)
}

#[allow(clippy::too_many_arguments)]
fn append_computer_event_with_payload(
    store: &mut LocalComputerSessionStore,
    session_id: &str,
    user: &UserId,
    workspace: &WorkspaceId,
    surface: SurfaceKind,
    kind: &str,
    status: &str,
    title: &str,
    subtitle: &str,
    payload: Value,
    approval_required: bool,
    artifact_refs: Vec<String>,
) -> Result<(), GatewayError> {
    store
        .append_event(&ComputerEventRecord {
            event_id: format!(
                "event_{}_{}",
                OffsetDateTime::now_utc().unix_timestamp_nanos(),
                kind
            ),
            session_id: session_id.to_string(),
            user_id: user.as_str().to_string(),
            workspace_id: workspace.as_str().to_string(),
            surface,
            kind: kind.to_string(),
            status: status.to_string(),
            title: title.to_string(),
            subtitle: subtitle.to_string(),
            payload,
            artifact_refs,
            approval_required,
            created_at: OffsetDateTime::now_utc(),
        })
        .map_err(GatewayError::local_computer)
}

fn default_computer_surfaces(now: OffsetDateTime) -> Vec<ComputerSurfaceRecord> {
    [
        (SurfaceKind::Browser, "Browser"),
        (SurfaceKind::Shell, "Terminale"),
        (SurfaceKind::Files, "File"),
        (SurfaceKind::Logs, "Log"),
    ]
    .into_iter()
    .map(|(surface, label)| ComputerSurfaceRecord {
        surface,
        label: label.to_string(),
        status: SurfaceStatus::Idle,
        detail: None,
        updated_at: now,
    })
    .collect()
}

fn surface_for_task(task: &TaskRecord) -> SurfaceKind {
    match task.kind.as_str() {
        "local_shell_task" => SurfaceKind::Shell,
        "browser_task" => SurfaceKind::Browser,
        kind if kind.starts_with("capability.browser.") => SurfaceKind::Browser,
        _ => SurfaceKind::Logs,
    }
}

fn browser_automation_dir() -> PathBuf {
    if let Ok(path) = env::var("HOMUN_BROWSER_AUTOMATION_DIR") {
        return PathBuf::from(path);
    }
    FsPath::new(env!("CARGO_MANIFEST_DIR"))
        .join("../../runtimes/browser-automation")
        .components()
        .collect()
}

/// Phase-1 default for the browser surface: HEADLESS.
///
/// Previously "0" (visible), which opened a real OS window that grabbed focus —
/// the behavior users dislike. Headless-by-default means the automated browser
/// runs invisibly; the user watches it *inside the chat* (the live frame view),
/// not as a window that takes over the desktop. This does NOT lose capability:
/// the sidecar's `restartAssistantVisible` self-heal still recovers the rare
/// site that genuinely fails headless, so it's "invisible by default, a window
/// only as a last resort" rather than "a window always". Override per install
/// with `HOMUN_BROWSER_HEADLESS=0`.
fn default_browser_headless_value() -> &'static str {
    "1"
}

fn browser_headless_env_value() -> String {
    env::var("HOMUN_BROWSER_HEADLESS")
        .unwrap_or_else(|_| default_browser_headless_value().to_string())
}

/// Resolves the contained-computer CDP endpoint (ADR 0010) from config, pure for
/// testability. An explicit `HOMUN_CONTAINED_COMPUTER_CDP` wins; otherwise
/// `HOMUN_CONTAINED_COMPUTER=1|true` enables the default local endpoint.
/// `None` means "use the on-host browser" (current default).
fn resolve_contained_computer_cdp(
    explicit: Option<&str>,
    enabled_flag: Option<&str>,
) -> Option<String> {
    if let Some(endpoint) = explicit.map(str::trim).filter(|value| !value.is_empty()) {
        return Some(endpoint.to_string());
    }
    let enabled = enabled_flag
        .map(|value| value == "1" || value.eq_ignore_ascii_case("true"))
        .unwrap_or(false);
    enabled.then(|| "http://127.0.0.1:9222".to_string())
}

/// Detects whether the contained computer container is currently running, with a
/// short-lived cache so the hot paths (every browse + the 1.5s live poll) don't
/// shell out to `docker ps` each time. Self-correcting: picks up the container
/// appearing/disappearing within the TTL. The first call probes synchronously for
/// a correct initial answer; later refreshes happen on a background thread so the
/// async live handler never blocks on the Docker CLI.
fn contained_container_detected() -> bool {
    use std::sync::{Mutex, OnceLock};
    use std::time::{Duration, Instant};

    struct Probe {
        value: bool,
        fetched_at: Option<Instant>,
        refreshing: bool,
    }
    static CACHE: OnceLock<Mutex<Probe>> = OnceLock::new();
    const TTL: Duration = Duration::from_secs(8);

    let cache = CACHE.get_or_init(|| {
        Mutex::new(Probe {
            value: false,
            fetched_at: None,
            refreshing: false,
        })
    });
    let mut guard = cache
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    let fresh = guard
        .fetched_at
        .map(|at| at.elapsed() < TTL)
        .unwrap_or(false);
    if fresh || guard.refreshing {
        return guard.value;
    }
    if guard.fetched_at.is_none() {
        // First call ever: probe synchronously so the initial answer is correct.
        let up = sandbox::container_up();
        guard.value = up;
        guard.fetched_at = Some(Instant::now());
        return up;
    }
    // Stale: refresh on a background thread, serve the last-known value now.
    guard.refreshing = true;
    drop(guard);
    std::thread::spawn(|| {
        let up = sandbox::container_up();
        if let Some(cache) = CACHE.get() {
            let mut guard = cache
                .lock()
                .unwrap_or_else(|poisoned| poisoned.into_inner());
            guard.value = up;
            guard.fetched_at = Some(Instant::now());
            guard.refreshing = false;
        }
    });
    cache
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner())
        .value
}

/// Resolves the contained computer's CDP endpoint. An explicit env endpoint wins;
/// then the `HOMUN_CONTAINED_COMPUTER` enable flag; otherwise we auto-detect
/// a running container — the app auto-starts it for skills, so the browser and the
/// live view should use it whenever it is up. `None` means "use the on-host
/// browser", the graceful fallback when Docker is unavailable.
fn contained_computer_cdp_endpoint() -> Option<String> {
    if let Some(endpoint) = resolve_contained_computer_cdp(
        env::var("HOMUN_CONTAINED_COMPUTER_CDP").ok().as_deref(),
        env::var("HOMUN_CONTAINED_COMPUTER").ok().as_deref(),
    ) {
        return Some(endpoint);
    }
    if contained_container_detected() {
        // Reuse the resolver's well-known default endpoint (DRY).
        return resolve_contained_computer_cdp(None, Some("true"));
    }
    None
}

/// The noVNC live-view URL for the contained computer (ADR 0010), or `None` when
/// contained mode is off. Pure for testability; the in-chat panel embeds this URL.
fn resolve_contained_computer_novnc(
    enabled: bool,
    explicit: Option<&str>,
    server_mode: bool,
) -> Option<String> {
    if !enabled {
        return None;
    }
    // Server build (the gateway serves the SPA): the container's noVNC port is
    // internal, so route the live view through the gateway's own proxy — a remote
    // browser loads it from the SAME public origin. A RELATIVE URL resolves against
    // whatever host/scheme the browser is already on. On desktop the loopback URL
    // is reachable directly, so keep embedding it (no proxy hop, no ticket).
    if server_mode {
        return Some("/api/computer/novnc/vnc.html".to_string());
    }
    Some(
        explicit
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or("http://127.0.0.1:6080/vnc.html")
            .to_string(),
    )
}

#[derive(Debug, Serialize)]
struct ContainedComputerLiveResponse {
    enabled: bool,
    /// Chat thread that owns the current live activity, if known.
    thread_id: Option<String>,
    novnc_url: Option<String>,
    /// True only while a browse_web is actually running right now.
    active: bool,
    /// The current activity (goal) when active, for the panel subtitle.
    activity: Option<String>,
    /// Steps executed so far — the live checklist ("Avanzamento attività").
    steps: Vec<BrowserStepView>,
    /// True while a CLI skill command is running in the contained computer.
    terminal_active: bool,
    /// Terminal commands + output for the current chat response (CLI skills).
    terminal: Vec<TerminalEntryView>,
}

#[derive(Serialize)]
struct LocalComputerActionResponse {
    ok: bool,
    enabled: bool,
    message: Option<String>,
}

/// Starts the contained computer on demand. Building/booting the container can
/// take a while (first run pulls/builds the image), so this is fire-and-forget:
/// it kicks off `ensure_contained_computer()` on a background thread and returns
/// immediately; the UI polls `/api/local-computer/live` for `enabled`.
async fn local_computer_start() -> Json<LocalComputerActionResponse> {
    if !sandbox::docker_running() {
        return Json(LocalComputerActionResponse {
            ok: false,
            enabled: sandbox::container_up(),
            message: Some("Docker is not available on this deployment.".to_string()),
        });
    }
    // An explicit START is a clear intent to use the container: reset the idle clock so
    // the reaper gives it a full window. Without this, if the gateway has been up a
    // while (idle timer already past the threshold) the reaper recycled the just-started
    // container within ~60s — the "I click start, it comes up, then it dies" report.
    touch_cc_activity();
    if sandbox::container_up() {
        return Json(LocalComputerActionResponse {
            ok: true,
            enabled: true,
            message: None,
        });
    }
    std::thread::spawn(|| {
        if let Err(error) = sandbox::ensure_contained_computer() {
            eprintln!("[local-computer] start failed: {error}");
        }
    });
    Json(LocalComputerActionResponse {
        ok: true,
        enabled: false,
        message: None,
    })
}

/// Stops and removes the contained computer (`docker rm -f`). Quick.
async fn local_computer_stop() -> Json<LocalComputerActionResponse> {
    let ok = tokio::task::spawn_blocking(sandbox::recycle_container)
        .await
        .unwrap_or(false);
    Json(LocalComputerActionResponse {
        ok,
        enabled: sandbox::container_up(),
        message: None,
    })
}

fn update_webhook() -> Option<String> {
    env::var("HOMUN_UPDATE_WEBHOOK")
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

#[derive(Serialize)]
struct UpdateInfoResponse {
    /// True on a server deploy where a redeploy webhook (Coolify/PaaS) is set —
    /// the only way a container can "update itself" is to ask the orchestrator
    /// to pull the new image and recreate it.
    webhook_configured: bool,
}

async fn update_info() -> Json<UpdateInfoResponse> {
    Json(UpdateInfoResponse {
        webhook_configured: update_webhook().is_some(),
    })
}

#[derive(Serialize)]
struct UpdateTriggerResponse {
    ok: bool,
    message: Option<String>,
}

/// Fires the configured redeploy webhook (e.g. Coolify) so the PaaS pulls the
/// latest image and recreates the container. The webhook URL stays server-side
/// (never shipped to the browser bundle).
async fn update_trigger(State(state): State<AppState>) -> Json<UpdateTriggerResponse> {
    let Some(webhook) = update_webhook() else {
        return Json(UpdateTriggerResponse {
            ok: false,
            message: Some("No update webhook configured (set HOMUN_UPDATE_WEBHOOK).".to_string()),
        });
    };
    match state
        .http
        .post(&webhook)
        .timeout(std::time::Duration::from_secs(15))
        .send()
        .await
    {
        Ok(response) if response.status().is_success() => Json(UpdateTriggerResponse {
            ok: true,
            message: None,
        }),
        Ok(response) => Json(UpdateTriggerResponse {
            ok: false,
            message: Some(format!("Webhook returned HTTP {}", response.status())),
        }),
        Err(error) => Json(UpdateTriggerResponse {
            ok: false,
            message: Some(format!("Webhook call failed: {error}")),
        }),
    }
}

/// Builds the contained computer live read-model: whether the live view is
/// available, where to embed it, whether the browser is working RIGHT NOW, and
/// the live step checklist. Shared by the `GET /api/local-computer/live` handler
/// and the Phase A background publisher (which pushes it on the unified WS
/// whenever its signature changes).
///
/// `touch_activity` should be true for the polled HTTP handler (watching counts
/// as activity, keeping the container from being recycled mid-view) and false
/// for the internal publisher (which fires regardless of whether a panel is
/// open, so it must not skew the idle timer).
/// Phase A background publisher: polls the contained computer live read-model
/// every 1s and broadcasts `computer.live` on the unified WS **only when its
/// JSON signature changes**. Replaces the client's 600ms-2.5s polling of
/// `GET /api/local-computer/live` with a server push. The signature guard
/// avoids spamming subscribers with identical frames during quiet periods.
fn spawn_computer_live_publisher(state: AppState) {
    tokio::spawn(async move {
        let mut last_signature = String::new();
        loop {
            tokio::time::sleep(std::time::Duration::from_millis(1000)).await;
            // `touch_activity = false`: the publisher fires unconditionally, so
            // touching the idle timer here would pin the container alive forever
            // (only an open panel/Local-computer page should reset it).
            let live = build_contained_computer_live(&state, false);
            let signature = serde_json::to_string(&live).unwrap_or_default();
            if signature != last_signature {
                last_signature = signature;
                if let Ok(value) = serde_json::to_value(&live) {
                    state.ws_registry.publish_computer_live(value);
                }
            }
        }
    });
}

fn build_contained_computer_live(state: &AppState, touch_activity: bool) -> ContainedComputerLiveResponse {
    if touch_activity {
        touch_cc_activity();
    }
    let mut novnc_url = resolve_contained_computer_novnc(
        contained_computer_cdp_endpoint().is_some(),
        env::var("HOMUN_CONTAINED_COMPUTER_NOVNC").ok().as_deref(),
        env::var("HOMUN_WEB_DIR")
            .map(|v| !v.trim().is_empty())
            .unwrap_or(false),
    );
    // A proxied (relative) URL means server mode → bake a stable ticket so the
    // embed's WebSocket authorizes against the gateway proxy. Desktop uses the
    // direct loopback URL and needs no ticket.
    if let Some(url) = novnc_url.as_mut() {
        if url.starts_with('/') {
            url.push_str(&format!(
                "?ticket={}",
                novnc_proxy::current_view_ticket(state)
            ));
        }
    }
    let activity_state = current_browser_activity();
    let raw_terminal = current_sandbox_activity();
    let terminal_active = raw_terminal.iter().any(|entry| entry.running);
    let terminal = if terminal_active {
        raw_terminal.clone()
    } else {
        Vec::new()
    };
    let owner_thread_id = activity_state
        .as_ref()
        .and_then(|state| state.thread_id.clone())
        .or_else(|| {
            if terminal_active {
                current_sandbox_owner().or_else(|| {
                    raw_terminal
                        .iter()
                        .rev()
                        .find_map(|entry| entry.thread_id.clone())
                })
            } else {
                None
            }
        });
    ContainedComputerLiveResponse {
        // The panel is useful for terminal activity even when the noVNC view is
        // not available, so report enabled when either surface has something.
        enabled: novnc_url.is_some() || terminal_active,
        thread_id: owner_thread_id,
        novnc_url,
        active: activity_state.is_some(),
        activity: activity_state.as_ref().map(|state| state.goal.clone()),
        steps: activity_state.map(|state| state.steps).unwrap_or_default(),
        terminal_active,
        terminal,
    }
}

/// Reports whether the contained computer's live view is available, where to
/// embed it, whether the browser is working RIGHT NOW, and the live step
/// checklist. Polled by the desktop panel.
async fn contained_computer_live(
    State(state): State<AppState>,
) -> Json<ContainedComputerLiveResponse> {
    // Watching the live view counts as activity. This endpoint is polled only while a
    // computer panel / the Local-computer page is open, so touching the idle timer here
    // keeps the container from being recycled out from under the user mid-view (the
    // reaper still reclaims it once nothing is viewing it for the idle window).
    Json(build_contained_computer_live(&state, true))
}

const CONTAINED_CONTAINER_NAME: &str = "homun-cc";

#[derive(Debug, Serialize)]
struct DockerStatus {
    installed: bool,
    running: bool,
    container_up: bool,
}

#[derive(Debug, Serialize)]
struct SystemStatusResponse {
    docker: DockerStatus,
    contained_enabled: bool,
    contained_cdp_ok: bool,
    gateway_memory_mb: u64,
    container_memory_mb: Option<u64>,
    browser_sessions: usize,
}

/// Run a CLI command, returning trimmed stdout on success (None otherwise).
fn run_cli(program: &str, args: &[&str]) -> Option<String> {
    std::process::Command::new(program)
        .args(args)
        .output()
        .ok()
        .filter(|output| output.status.success())
        .map(|output| String::from_utf8_lossy(&output.stdout).trim().to_string())
}

/// Resident memory of THIS gateway process, in MB (best-effort via `ps`).
fn gateway_memory_mb() -> u64 {
    let pid = std::process::id().to_string();
    run_cli("ps", &["-o", "rss=", "-p", &pid])
        .and_then(|stdout| stdout.split_whitespace().next().map(str::to_string))
        .and_then(|kb| kb.parse::<u64>().ok())
        .map(|kb| kb / 1024)
        .unwrap_or(0)
}

/// Parse the first figure of a `docker stats` MemUsage cell (e.g. "123.4MiB / 512MiB").
fn parse_docker_mem_mb(usage: &str) -> Option<u64> {
    let first = usage.split('/').next()?.trim();
    let digits: String = first
        .chars()
        .take_while(|c| c.is_ascii_digit() || *c == '.')
        .collect();
    let value: f64 = digits.parse().ok()?;
    let mb = if first.contains("GiB") || first.contains("GB") {
        value * 1024.0
    } else if first.contains("KiB") || first.contains("KB") {
        value / 1024.0
    } else {
        value // MiB/MB
    };
    Some(mb.round() as u64)
}

/// Is the contained-computer CDP responding? `/json/version` with a short timeout. Returns
/// true when there's no contained CDP (host-browser mode → nothing to heal). The self-heal
/// gate before connecting the browser sidecar.
async fn browser_cdp_ok(state: &AppState) -> bool {
    let Some(endpoint) = contained_computer_cdp_endpoint() else {
        return true;
    };
    state
        .http
        .get(format!("{}/json/version", endpoint.trim_end_matches('/')))
        .timeout(std::time::Duration::from_millis(1500))
        .send()
        .await
        .map(|r| r.status().is_success())
        .unwrap_or(false)
}

/// Self-heal a wedged browser: if the contained-computer CDP doesn't answer (Chrome
/// alive-but-stuck, or the container died), recycle the container (`docker rm -f`) and
/// recreate it, then wait for CDP to come back. No-op (fast) when already healthy.
async fn ensure_browser_cdp_healthy(state: &AppState) -> bool {
    if browser_cdp_ok(state).await {
        return true;
    }
    let _ = tokio::task::spawn_blocking(|| {
        crate::sandbox::recycle_container();
        let _ = crate::sandbox::ensure_contained_computer();
    })
    .await;
    // Poll for Chrome to relaunch + bind CDP (cold container start).
    for _ in 0..40 {
        tokio::time::sleep(std::time::Duration::from_millis(1000)).await;
        if browser_cdp_ok(state).await {
            return true;
        }
    }
    false
}

/// UNCONDITIONAL recycle of the contained computer, for the CDP WEDGE: Chrome's HTTP
/// `/json/version` still answers (so `browser_cdp_ok` returns true and
/// `ensure_browser_cdp_healthy` is a no-op) yet `connectOverCDP` hangs on stale targets.
/// Throttled (once per window) so a retry loop can't thrash `docker rm -f`. Returns true
/// if CDP came back. Mirrors the drive's shared-path self-heal for motore #1's chat path.
async fn force_recycle_contained_computer(state: &AppState) -> bool {
    if !browser_recycle_throttle_ok() {
        return false;
    }
    let _ = tokio::task::spawn_blocking(|| {
        crate::sandbox::recycle_container();
        let _ = crate::sandbox::ensure_contained_computer();
    })
    .await;
    for _ in 0..40 {
        tokio::time::sleep(std::time::Duration::from_millis(1000)).await;
        if browser_cdp_ok(state).await {
            return true;
        }
    }
    false
}

/// System/Computer status for Settings: Docker (installed/running + the contained
/// computer container), tool memory usage, live browser-session count.
async fn system_status(State(state): State<AppState>) -> Json<SystemStatusResponse> {
    let browser_sessions = state
        .browser_thread_sessions
        .lock()
        .map(|map| map.len())
        .unwrap_or(0);
    let cdp = contained_computer_cdp_endpoint();
    let contained_enabled = cdp.is_some();
    let contained_cdp_ok = if let Some(endpoint) = cdp.as_ref() {
        state
            .http
            .get(format!("{}/json/version", endpoint.trim_end_matches('/')))
            .timeout(std::time::Duration::from_millis(800))
            .send()
            .await
            .map(|response| response.status().is_success())
            .unwrap_or(false)
    } else {
        false
    };
    let (docker, gateway_mb, container_mb) = tokio::task::spawn_blocking(|| {
        let installed = run_cli("docker", &["--version"]).is_some();
        let running =
            installed && run_cli("docker", &["info", "--format", "{{.ServerVersion}}"]).is_some();
        let filter = format!("name={CONTAINED_CONTAINER_NAME}");
        let container_up = running
            && run_cli(
                "docker",
                &["ps", "--filter", &filter, "--format", "{{.Names}}"],
            )
            .map(|names| names.contains(CONTAINED_CONTAINER_NAME))
            .unwrap_or(false);
        let container_mb = if container_up {
            run_cli(
                "docker",
                &[
                    "stats",
                    "--no-stream",
                    "--format",
                    "{{.MemUsage}}",
                    CONTAINED_CONTAINER_NAME,
                ],
            )
            .as_deref()
            .and_then(parse_docker_mem_mb)
        } else {
            None
        };
        (
            DockerStatus {
                installed,
                running,
                container_up,
            },
            gateway_memory_mb(),
            container_mb,
        )
    })
    .await
    .unwrap_or((
        DockerStatus {
            installed: false,
            running: false,
            container_up: false,
        },
        0,
        None,
    ));

    Json(SystemStatusResponse {
        docker,
        contained_enabled,
        contained_cdp_ok,
        gateway_memory_mb: gateway_mb,
        container_memory_mb: container_mb,
        browser_sessions,
    })
}

#[derive(Debug, Serialize)]
struct CloseAllBrowsersResponse {
    closed_sessions: usize,
    closed_tabs: usize,
}

/// Close every per-thread browser session AND any lingering page in the contained
/// browser. Exposed in Settings as "Chiudi tutti i browser".
async fn close_all_browsers(State(state): State<AppState>) -> Json<CloseAllBrowsersResponse> {
    let sessions: Vec<ThreadBrowserSession> = state
        .browser_thread_sessions
        .lock()
        .map(|mut map| map.drain().map(|(_, session)| session).collect())
        .unwrap_or_default();
    let closed_sessions = sessions.len();
    let _ = tokio::task::spawn_blocking(move || {
        for session in sessions {
            let _ = session
                .client
                .call(BrowserMethod::Stop, serde_json::json!({}));
        }
    })
    .await;

    let mut closed_tabs = 0usize;
    if let Some(endpoint) = contained_computer_cdp_endpoint() {
        let base = endpoint.trim_end_matches('/').to_string();
        if let Ok(response) = state
            .http
            .get(format!("{base}/json"))
            .timeout(std::time::Duration::from_secs(2))
            .send()
            .await
        {
            if let Ok(targets) = response.json::<Vec<serde_json::Value>>().await {
                for target in targets {
                    if target.get("type").and_then(Value::as_str) != Some("page") {
                        continue;
                    }
                    let Some(id) = target.get("id").and_then(Value::as_str) else {
                        continue;
                    };
                    let closed = state
                        .http
                        .get(format!("{base}/json/close/{id}"))
                        .timeout(std::time::Duration::from_secs(2))
                        .send()
                        .await
                        .map(|response| response.status().is_success())
                        .unwrap_or(false);
                    if closed {
                        closed_tabs += 1;
                    }
                }
            }
        }
    }

    Json(CloseAllBrowsersResponse {
        closed_sessions,
        closed_tabs,
    })
}

/// Env for the browser sidecar, shared by every spawn site so contained-computer
/// mode can never be wired into one path and missed in another. In contained
/// mode we add the CDP endpoint of the in-container real browser; the sidecar
/// then attaches via connectOverCDP instead of launching a host Chromium.
fn browser_sidecar_env(state: &AppState, task: &TaskRecord) -> Vec<(String, String)> {
    browser_sidecar_env_with_headless(browser_headless_env_value_for_task(state, task))
}

/// Sidecar env for a CHAT-driven browser session (granular tools): same env as the
/// task path (artifact root, CDP endpoint, isolated-context opt-in, allow-private-
/// network via the sidecar default) but WITHOUT a TaskRecord — there is no task to
/// derive visibility from, so the global headless default is used.
fn browser_sidecar_env_for_chat() -> Vec<(String, String)> {
    browser_sidecar_env_with_headless(browser_headless_env_value())
}

/// Shared sidecar env builder. PRESERVE every var here when adding new spawn
/// callers — only the headless value differs between task and chat sessions.
fn browser_sidecar_env_with_headless(headless: String) -> Vec<(String, String)> {
    let artifact_root = env::temp_dir().join("local-first-browser-artifacts");
    let mut env = vec![
        ("BROWSER_AUTOMATION_HEADLESS".to_string(), headless),
        (
            "BROWSER_AUTOMATION_ARTIFACT_ROOT".to_string(),
            artifact_root.display().to_string(),
        ),
    ];
    // Where a PERSISTENT assistant profile would live (under the data dir, not tmp).
    // Persistence is OPT-IN (BROWSER_AUTOMATION_PERSIST_PROFILE=1): by default the
    // runtime ignores this and uses an ephemeral per-run profile, so anonymous
    // searches never inherit a once-flagged "bot" fingerprint (the flights/trains
    // block). Set it for authenticated flows where a returning logged-in identity
    // helps. Harmless when unset.
    if let Ok(dir) = gateway_data_dir() {
        env.push((
            "BROWSER_AUTOMATION_PROFILE_ROOT".to_string(),
            dir.join("browser-automation").display().to_string(),
        ));
    }
    if let Some(endpoint) = contained_computer_cdp_endpoint() {
        env.push(("BROWSER_AUTOMATION_USER_CDP_ENDPOINT".to_string(), endpoint));
        // Isolated context is OFF by default: measured that a fresh ("cold")
        // context regresses reliability (no cookies -> consent/geo walls ->
        // the worker wanders and burns iterations). The default warm shared
        // context is far more reliable. Isolation is opt-in per worker (set via
        // HOMUN_BROWSER_PARALLEL when fanning out) — see parallel path.
        if env::var("HOMUN_BROWSER_ISOLATED_CONTEXT").as_deref() == Ok("1") {
            env.push((
                "BROWSER_AUTOMATION_ISOLATED_CONTEXT".to_string(),
                "1".to_string(),
            ));
        }
    }
    env
}

fn browser_headless_env_value_for_task(state: &AppState, task: &TaskRecord) -> String {
    let fallback = browser_headless_env_value();
    browser_visibility_for_task(state, task).headless_env_value(&fallback)
}

fn browser_visibility_for_task(state: &AppState, task: &TaskRecord) -> BrowserVisibilityMode {
    if !task_uses_browser(task) {
        return BrowserVisibilityMode::Auto;
    }
    let latest_checkpoint_visibility = task
        .checkpoint_json
        .as_ref()
        .and_then(|checkpoint| checkpoint.get("browser_visibility"))
        .and_then(Value::as_str)
        .map(|value| parse_browser_visibility(Some(value)))
        .filter(|visibility| *visibility != BrowserVisibilityMode::Auto);
    if let Some(visibility) = latest_checkpoint_visibility {
        return visibility;
    }

    let Ok(policy_store) = lock_browser_url_policies(state) else {
        return BrowserVisibilityMode::Auto;
    };
    for target in browser_targets_for_goal(&task_effective_goal(task)) {
        let Ok(Some(rule)) = policy_store.rule_for_url(
            gateway_user_id().as_str(),
            gateway_workspace_id().as_str(),
            &target.url,
            "navigate",
        ) else {
            continue;
        };
        if rule.visibility != BrowserVisibilityMode::Auto {
            return rule.visibility;
        }
    }
    BrowserVisibilityMode::Auto
}

fn task_uses_browser(task: &TaskRecord) -> bool {
    task.kind == "browser_task"
        || task.kind.starts_with("capability.browser.")
        || task
            .resource_requirements
            .iter()
            .any(|resource| resource.class == ResourceClass::BrowserSession)
}

fn parse_approval_scope(value: Option<&str>) -> BrowserUrlApprovalScope {
    match value {
        Some("always") => BrowserUrlApprovalScope::Always,
        _ => BrowserUrlApprovalScope::Once,
    }
}

fn parse_browser_visibility(value: Option<&str>) -> BrowserVisibilityMode {
    match value {
        Some("headless") => BrowserVisibilityMode::Headless,
        Some("visible") => BrowserVisibilityMode::Visible,
        _ => BrowserVisibilityMode::Auto,
    }
}

fn approval_scope_label(value: BrowserUrlApprovalScope) -> &'static str {
    match value {
        BrowserUrlApprovalScope::Once => "once",
        BrowserUrlApprovalScope::Always => "always",
    }
}

fn browser_visibility_label(value: BrowserVisibilityMode) -> &'static str {
    match value {
        BrowserVisibilityMode::Auto => "auto",
        BrowserVisibilityMode::Headless => "headless",
        BrowserVisibilityMode::Visible => "visible",
    }
}

#[derive(Debug, Clone)]
struct BrowserTarget {
    label: String,
    url: String,
}

/// ONE general entry for every goal: a web search of the goal. The model-driven
/// observe-act loop navigates from there. No keyword/domain/transport routing —
/// the model understands what the goal needs and decides where to go.
fn browser_targets_for_goal(goal: &str) -> Vec<BrowserTarget> {
    vec![BrowserTarget {
        label: "Web search".to_string(),
        url: browser_url_for_goal(goal),
    }]
}

fn browser_url_for_goal(goal: &str) -> String {
    // Uniform entry for EVERY goal: a web search of the goal verbatim. No
    // keyword/site special-casing — the observe-act loop navigates from the
    // results to wherever the goal actually leads.
    format!("https://duckduckgo.com/?q={}", url_encode(goal))
}

fn url_encode(value: &str) -> String {
    let mut encoded = String::new();
    for byte in value.bytes() {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                encoded.push(byte as char)
            }
            b' ' => encoded.push('+'),
            _ => encoded.push_str(&format!("%{byte:02X}")),
        }
    }
    encoded
}

fn truncate_chars(value: &str, max_chars: usize) -> String {
    let mut truncated = value.chars().take(max_chars).collect::<String>();
    if value.chars().count() > max_chars {
        truncated.push_str("\n...");
    }
    truncated
}

fn evaluate_simple_arithmetic(text: &str) -> Option<String> {
    let expression = text
        .chars()
        .filter(|char| {
            char.is_ascii_digit() || matches!(char, '+' | '-' | '*' | '/' | 'x' | 'X' | ' ' | '.')
        })
        .collect::<String>()
        .replace(['x', 'X'], "*");
    let compact = expression.split_whitespace().collect::<String>();
    if compact.is_empty()
        || !compact
            .chars()
            .any(|char| matches!(char, '+' | '-' | '*' | '/'))
    {
        return None;
    }
    let (left, operator, right) = split_binary_expression(&compact)?;
    let left = left.parse::<f64>().ok()?;
    let right = right.parse::<f64>().ok()?;
    let value = match operator {
        '+' => left + right,
        '-' => left - right,
        '*' => left * right,
        '/' if right != 0.0 => left / right,
        '/' => return None,
        _ => return None,
    };
    if value.fract() == 0.0 {
        Some(format!("{}", value as i64))
    } else {
        Some(
            format!("{value:.4}")
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string(),
        )
    }
}

fn split_binary_expression(expression: &str) -> Option<(&str, char, &str)> {
    for operator in ['*', '/', '+', '-'] {
        if let Some(index) = expression[1..].find(operator).map(|index| index + 1) {
            let left = &expression[..index];
            let right = &expression[index + 1..];
            if !left.is_empty() && !right.is_empty() {
                return Some((left, operator, right));
            }
        }
    }
    None
}

fn task_goal_summary(goal: &str) -> String {
    let redacted = redact_sensitive_text(goal)
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ");
    let compact = if redacted.contains("[REDACTED]") {
        compact_redacted_task_goal_summary(&redacted)
    } else {
        compact_thread_title(&redacted)
    };
    if compact.is_empty() {
        "Local task from chat".to_string()
    } else {
        compact
    }
}

fn compact_redacted_task_goal_summary(redacted: &str) -> String {
    const MAX_CHARS: usize = 44;

    let marker_segment = redacted
        .split_whitespace()
        .find(|word| word.contains("[REDACTED]"))
        .unwrap_or("[REDACTED]");
    if marker_segment.chars().count() >= MAX_CHARS {
        return marker_segment.chars().take(MAX_CHARS).collect();
    }

    let prefix = redacted
        .find(marker_segment)
        .map(|index| redacted[..index].trim())
        .unwrap_or_default();
    let compact_prefix = compact_thread_title(prefix);
    let separator_chars = usize::from(!compact_prefix.is_empty());
    let prefix_budget = MAX_CHARS
        .saturating_sub(marker_segment.chars().count())
        .saturating_sub(separator_chars);
    let prefix = compact_prefix
        .chars()
        .take(prefix_budget)
        .collect::<String>()
        .trim()
        .to_string();

    if prefix.is_empty() {
        marker_segment.to_string()
    } else {
        format!("{prefix} {marker_segment}")
    }
}

fn task_effective_goal(task: &TaskRecord) -> String {
    task.input_json
        .get("prompt_redacted")
        .and_then(Value::as_str)
        .filter(|value| !value.trim().is_empty())
        .unwrap_or(task.goal.as_str())
        .to_string()
}

fn capability_snapshot_response(
    registry: &CapabilityRegistryStore,
    user: &CapabilityUserId,
    workspace: &CapabilityWorkspaceId,
    policy: PolicyContext,
) -> Result<CapabilitySnapshotResponse, GatewayError> {
    let connections = registry
        .connection_configs(user, workspace)
        .map_err(GatewayError::capability)?
        .into_iter()
        .map(capability_connection_response)
        .collect::<Result<Vec<_>, _>>()?;

    let mut tools = Vec::new();
    for provider in &policy.enabled_providers {
        for cached in registry
            .cached_tools(provider)
            .map_err(GatewayError::capability)?
        {
            tools.push(capability_tool_response(cached)?);
        }
    }
    tools.sort_by(|left, right| {
        left.provider_id
            .cmp(&right.provider_id)
            .then(left.name.cmp(&right.name))
    });

    Ok(CapabilitySnapshotResponse {
        connections,
        tools,
        policy: CapabilityPolicyResponse {
            enabled_providers: policy
                .enabled_providers
                .into_iter()
                .map(|provider| provider.as_str().to_string())
                .collect(),
            allow_managed_cloud: policy.allow_managed_cloud,
            privacy_domains: policy.privacy_domains,
            max_autonomy_level: policy.max_autonomy_level,
        },
    })
}

fn capability_connection_response(
    config: CapabilityConnectionConfig,
) -> Result<CapabilityConnectionResponse, GatewayError> {
    Ok(CapabilityConnectionResponse {
        id: config.connection_id,
        provider_id: config.provider_id.as_str().to_string(),
        display_name: config.display_name,
        status: enum_label(&config.status)?,
        privacy_domains: config.privacy_domains,
        metadata: config.metadata,
    })
}

fn capability_tool_response(
    cached: CachedCapabilityTool,
) -> Result<CapabilityToolResponse, GatewayError> {
    Ok(CapabilityToolResponse {
        provider_id: cached.tool.provider_id.as_str().to_string(),
        name: cached.tool.name,
        provider_kind: enum_label(&cached.tool.provider_kind)?,
        action: enum_label(&cached.tool.action)?,
        description: cached.tool.description,
        privacy_domains: cached.tool.privacy_domains,
        sensitivity: cached.tool.sensitivity,
    })
}

fn open_seeded_capability_registry() -> Result<CapabilityRegistryStore, std::io::Error> {
    let registry = CapabilityRegistryStore::open(gateway_capability_database_path()?)
        .map_err(|error| std::io::Error::other(error.to_string()))?;
    seed_default_capabilities(&registry)
        .map_err(|error| std::io::Error::other(error.to_string()))?;
    Ok(registry)
}

fn seed_default_capabilities(
    registry: &CapabilityRegistryStore,
) -> Result<(), local_first_capabilities::CapabilityError> {
    let browser_provider = CapabilityProviderId::new("browser");
    registry.upsert_provider_config(&CapabilityProviderConfig::new(
        browser_provider.clone(),
        CapabilityProviderKind::Browser,
        "My browser".to_string(),
        true,
    ))?;
    registry.upsert_provider_grant(
        &CapabilityProviderGrant::new(
            browser_provider.clone(),
            gateway_capability_user_id(),
            gateway_capability_workspace_id(),
        )
        .with_privacy_domains(vec!["browser".to_string(), "local".to_string()])
        .with_allowed_actions(vec![ActionClass::Read, ActionClass::WriteWithConfirmation])
        .with_max_autonomy_level(3),
    )?;
    registry.upsert_connection_config(
        &CapabilityConnectionConfig::new(
            "browser-local",
            browser_provider.clone(),
            gateway_capability_user_id(),
            gateway_capability_workspace_id(),
            "My browser",
            "local-browser-profile",
        )
        .with_privacy_domains(vec!["browser".to_string()])
        .with_metadata(serde_json::json!({
            "data_boundary": "local",
            "transport": "playwright_cdp",
            "requires_confirmation": true
        })),
    )?;

    // (F1.d / ADR 0020) Seed the browser provider with the SAME six tools the chat loop
    // offers the model — `browser_navigate`/`_snapshot`/`_act`/`_tabs`/`_screenshot`/
    // `_dialog`, with their REAL schemas — NOT the low-level dot-named sidecar methods with
    // placeholder `{"type":"object"}` schemas it used to carry. The orchestrator planner
    // indexes the registry's cached tools (`cached_tools`); seeding the executable model
    // tools is what makes the planner finally SEE the browser as a routable capability whose
    // names match what the chat loop actually runs, instead of a shadow set it can't use.
    // Clear first so an existing DB sheds the renamed `browser.*` rows (caposaldo #5/#7).
    registry.clear_cached_tools(&browser_provider)?;
    for tool in browser_registry_cached_tools() {
        registry.upsert_cached_tool(&tool)?;
    }
    Ok(())
}

/// The browser capability AS THE MODEL SEES IT: the six chat browser tools with their real
/// names + schemas, built from the SAME `browser_*_tool_schema()` functions the live tool
/// set uses, so the registry never becomes a second source of truth for the browser surface
/// (caposaldo #5). Read vs WriteWithConfirmation mirrors the chat safety posture: reading
/// the page (snapshot/tabs/screenshot) is Read; navigating, acting and answering dialogs can
/// have side effects → WriteWithConfirmation.
fn browser_registry_cached_tools() -> Vec<CachedCapabilityTool> {
    let browser_provider = CapabilityProviderId::new("browser");
    [
        (
            browser_navigate_tool_schema(),
            ActionClass::WriteWithConfirmation,
        ),
        (browser_snapshot_tool_schema(), ActionClass::Read),
        (
            browser_act_tool_schema(),
            ActionClass::WriteWithConfirmation,
        ),
        (browser_tabs_tool_schema(), ActionClass::Read),
        (browser_screenshot_tool_schema(), ActionClass::Read),
        (
            browser_dialog_tool_schema(),
            ActionClass::WriteWithConfirmation,
        ),
    ]
    .into_iter()
    .filter_map(|(schema, action)| {
        let function = schema.get("function")?;
        let name = function.get("name")?.as_str()?.to_string();
        let description = function
            .get("description")
            .and_then(|value| value.as_str())
            .unwrap_or("")
            .to_string();
        let input_schema = function
            .get("parameters")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({"type": "object"}));
        Some(CachedCapabilityTool::new(
            browser_provider.clone(),
            name,
            CapabilityProviderKind::Browser,
            action,
            description,
            vec!["browser".to_string()],
            "private",
            input_schema,
        ))
    })
    .collect()
}

fn enum_label(value: &impl Serialize) -> Result<String, GatewayError> {
    serde_json::to_value(value)
        .map_err(|error| GatewayError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            code: "enum_serialize_failed",
            message: error.to_string(),
        })?
        .as_str()
        .map(str::to_string)
        .ok_or_else(|| GatewayError {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            code: "enum_serialize_failed",
            message: "enum did not serialize to string".to_string(),
        })
}

fn resource_class_label(resource: ResourceClass) -> &'static str {
    resource.as_str()
}

fn redact_sensitive_text(input: &str) -> String {
    let mut output = strip_terminal_control_sequences(input);
    for marker in [
        "sk-",
        "sk_proj_",
        "token=",
        "Authorization:",
        "Bearer ",
        "password=",
        "secret=",
    ] {
        if let Some(index) = output.to_lowercase().find(&marker.to_lowercase()) {
            output.truncate(index + marker.len());
            output.push_str("[REDACTED]");
            return output;
        }
    }
    output
}

fn strip_terminal_control_sequences(input: &str) -> String {
    let mut output = String::with_capacity(input.len());
    let mut chars = input.chars().peekable();
    while let Some(char) = chars.next() {
        if char == '\u{1b}' {
            if chars.peek() == Some(&'[') {
                chars.next();
                for next in chars.by_ref() {
                    if ('@'..='~').contains(&next) {
                        break;
                    }
                }
            }
            continue;
        }
        if char.is_control() && char != '\n' && char != '\t' {
            continue;
        }
        output.push(char);
    }
    output
}

#[derive(Debug)]
struct GatewayError {
    status: StatusCode,
    code: &'static str,
    message: String,
}

impl GatewayError {
    fn store(error: rusqlite::Error) -> Self {
        Self {
            status: StatusCode::INTERNAL_SERVER_ERROR,
            code: "chat_store_error",
            message: error.to_string(),
        }
    }

    fn task(error: local_first_task_runtime::TaskRuntimeError) -> Self {
        Self {
            status: StatusCode::BAD_GATEWAY,
            code: "task_runtime_error",
            message: error.to_string(),
        }
    }

    fn local_computer(error: String) -> Self {
        Self {
            status: StatusCode::BAD_GATEWAY,
            code: "local_computer_error",
            message: error,
        }
    }

    fn memory(error: String) -> Self {
        Self {
            status: StatusCode::BAD_GATEWAY,
            code: "memory_error",
            message: error,
        }
    }

    fn capability(error: local_first_capabilities::CapabilityError) -> Self {
        Self {
            status: StatusCode::BAD_GATEWAY,
            code: "capability_error",
            message: error.to_string(),
        }
    }
}

